import React from 'react';
import { AppSettings } from '../types';

interface Props {
  settings: AppSettings;
}

const GasGenerator: React.FC<Props> = ({ settings }) => {
  const hasKeys = settings.geminiKey && settings.lineToken;

  const gasCode = `
/**
 * 台灣股市 AI 分析師 - 自動化腳本
 * 請將此代碼複製到 Google Apps Script (https://script.google.com/)
 */

// --- 設定區 ---
const GEMINI_API_KEY = "${settings.geminiKey || '請在此填入您的 Gemini API Key'}";
const LINE_TOKEN = "${settings.lineToken || '請在此填入您的 LINE Notify Token'}";
const MODEL_NAME = "gemini-2.5-flash-latest"; // 使用穩定且快速的模型

// --- 主程式：請設定「觸發條件」每天早上 8:50 執行此函式 ---
function dailyStockScan() {
  Logger.log("開始執行晨間掃描...");

  try {
    // 1. 呼叫 Gemini 分析股票
    const recommendations = fetchGeminiRecommendations();

    if (!recommendations || recommendations.length === 0) {
      Logger.log("未找到推薦股票或分析失敗");
      return;
    }

    // 2. 格式化訊息
    let message = "\\n【早安！AI 每日潛力股掃描】\\n";
    message += "--------------------------------\\n";

    recommendations.forEach((stock, index) => {
      message += \`\${index + 1}. \${stock.name} (\${stock.symbol})\n\`;
      message += \`   現價: \${stock.currentPrice} | 買點: \${stock.buyPoint}\n\`;
      message += \`   理由: \${stock.reason}\n\`;
      message += "--------------------------------\\n";
    });

    message += "\\n詳細分析請查看儀表板。";

    // 3. 發送 LINE 通知
    sendLineNotify(message);

  } catch (e) {
    Logger.log("發生錯誤: " + e.toString());
    sendLineNotify("⚠️ 系統執行發生錯誤，請檢查 Google Apps Script 日誌。");
  }
}

function fetchGeminiRecommendations() {
  const url = \`https://generativelanguage.googleapis.com/v1beta/models/\${MODEL_NAME}:generateContent?key=\${GEMINI_API_KEY}\`;

  const systemPrompt = \`
    角色設定：你是一位擁有20年經驗的資深台股分析師。
    任務：掃描當前台灣股市狀況，找出 10 支股價在 50 元以下，且你看漲的優質潛力股。
    格式：回傳純 JSON 陣列，不要有 Markdown 標記。
    Schema: [{ "symbol": string, "name": string, "currentPrice": number, "buyPoint": number, "reason": string }]
  \`;

  const payload = {
    contents: [{
      parts: [{
        text: "找出 10 支股價 < 50 TWD 的潛力股，分析技術面與基本面，給出建議買入點。"
      }]
    }],
    systemInstruction: {
      parts: [{ text: systemPrompt }]
    },
    generationConfig: {
      responseMimeType: "application/json"
    },
    // 注意：GAS 環境中使用 Google Search Tool 較為複雜，此處使用基本模型知識庫
    // 若需即時聯網，需確認 GAS 專案是否具備相關權限或使用 Custom Search API
  };

  const options = {
    method: "post",
    contentType: "application/json",
    payload: JSON.stringify(payload),
    muteHttpExceptions: true
  };

  const response = UrlFetchApp.fetch(url, options);
  const responseCode = response.getResponseCode();
  const responseText = response.getContentText();

  if (responseCode !== 200) {
    throw new Error(\`Gemini API Error (\${responseCode}): \${responseText}\`);
  }

  const json = JSON.parse(responseText);
  const contentText = json.candidates?.[0]?.content?.parts?.[0]?.text;

  if (!contentText) return [];

  // 清理可能存在的 Markdown code block 標記
  const cleanJson = contentText.replace(/\\`\\`\\`json/g, "").replace(/\\`\\`\\`/g, "").trim();

  return JSON.parse(cleanJson);
}

function sendLineNotify(message) {
  const url = "https://notify-api.line.me/api/notify";
  const options = {
    method: "post",
    headers: {
      "Authorization": "Bearer " + LINE_TOKEN
    },
    payload: {
      "message": message
    }
  };

  UrlFetchApp.fetch(url, options);
  Logger.log("LINE 通知已發送");
}
`;

  const copyToClipboard = () => {
    navigator.clipboard.writeText(gasCode).then(() => {
      alert("程式碼已複製到剪貼簿！");
    });
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-cardBg rounded-xl p-6 shadow-xl border-l-4 border-purple-500">
        <h2 className="text-2xl font-bold text-white mb-2">Google Apps Script 自動化整合</h2>
        <p className="text-gray-400">
