interface Props {
  apiKey: string;
}

const AnalysisView: React.FC<Props> = ({ apiKey }) => {
  const [stockSymbol, setStockSymbol] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState('');
  const [fugleKey, setFugleKey] = useState('');

  useEffect(() => {
    const saved = localStorage.getItem('twStockAppSettings');
    if (saved) {
      const parsed = JSON.parse(saved);
      setFugleKey(parsed.fugleKey || '');
    }
  }, []);

  const handleAnalyze = async () => {
    if (!stockSymbol) return;
    if (!apiKey) {
      setError('請先至「設定」輸入 Gemini API Key');
      return;
    }

    setLoading(true);
    setError('');
    setResult(null);

    try {
      let currentPrice = 0;
      let priceSource = '模擬數據';

      // 1. Try to get real price from Fugle
      if (fugleKey) {
        const realPrice = await fetchFuglePrice(stockSymbol, fugleKey);
        if (realPrice) {
          currentPrice = realPrice;
          priceSource = 'Fugle Realtime';
        }
      }

      // 2. If no Fugle key or fetch failed, warn user or use 0 to let Gemini search
      if (currentPrice === 0) {
        if (!fugleKey) {
             // If no key, we pass 0 and let Gemini try to find it, but strictly it might fail to be accurate.
             // We'll proceed but the prompt in geminiService should ideally handle "0" by searching.
             // However, for this fix, we assume user provides key or we accept potential inaccuracy.
             console.warn("No Fugle Key provided, analysis might rely on LLM internal knowledge.");
        }
      }

      const analysis = await analyzeSingleStock(apiKey, stockSymbol, currentPrice);
      setResult(analysis);
    } catch (err: any) {
      setError(err.message || '分析失敗，請稍後再試');
    } finally {
      setLoading(false);
    }
