    // In a real app, this would be a loop or interval.
    // We check the first stock for demo purposes.
    const hitStock = currentStocks[0]; 
    if (hitStock) {
       // Just a simulation logic for the demo UI
       const msg = `【觸發買點通知】\n股票：${hitStock.name} (${hitStock.symbol})\n建議買點：${hitStock.buyPoint}\n原因：${hitStock.reason}`;
       addLog(`🚀 ${hitStock.name} 觸發買點，發送 LINE 通知...`);
       const sent = await sendLineNotification(settings.lineChannelToken, settings.lineUserId, msg);
       if (sent) addLog("✅ LINE 通知發送成功");
       else addLog("❌ LINE 通知發送失敗");
    }
  };

  const addLog = (msg: string) => {
    setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);
  };

  const handleMorningScan = async () => {
    if (!settings.geminiKey) {
      alert("請先設定 Gemini API Key");
      return;
    }

    setLoading(true);
    setScanTime(null);
    setLogs([]); // Clear logs
    addLog("開始執行晨間掃描 (8:50 AM 模擬)...");

    try {
      // 1. Get Recommendations from Gemini (Discovery Phase)
      addLog("🤖 AI 正在掃描市場潛力股...");
      const recs = await getDailyRecommendations(settings.geminiKey);

      let finalStocks = recs;

      // 2. Refresh Prices using Fugle API if available (Validation Phase)
      if (settings.fugleKey) {
        addLog("📊 正在透過 Fugle API 更新即時股價...");
        const updatedStocks = await Promise.all(recs.map(async (stock) => {
          const realPrice = await fetchFuglePrice(stock.symbol, settings.fugleKey);
          if (realPrice) {
            return { ...stock, currentPrice: realPrice };
          }
          return stock;
        }));
        finalStocks = updatedStocks;
      } else {
        addLog("⚠️ 未設定 Fugle Key，顯示價格可能非最新即時數據");
      }

      setStocks(finalStocks);
      setScanTime(new Date().toLocaleTimeString());
      addLog(`掃描完成，找到 ${finalStocks.length} 支潛力股`);

      // Auto start monitoring if we have results
      setMonitoring(true);

      // Simulate the check immediately for demo
      setTimeout(() => checkPrices(finalStocks), 2000);

    } catch (e) {
      console.error(e);
      addLog("❌ 掃描失敗");
      alert("掃描失敗，請檢查 API Key 或網路");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center bg-cardBg p-6 rounded-xl shadow-lg border-l-4 border-blue-500">
        <div>
          <h2 className="text-2xl font-bold text-white">市場掃描監控台</h2>
          <p className="text-gray-400 mt-1">
            自動分析股價小於 50 元的潛力股，並監控進場點。
            {scanTime && <span className="ml-2 text-green-400 text-sm">上次掃描: {scanTime}</span>}
          </p>
        </div>
        <button
          onClick={handleMorningScan}
          disabled={loading}
          className={`px-6 py-3 rounded-lg font-bold text-white transition-all ${
            loading ? 'bg-gray-600' : 'bg-blue-600 hover:bg-blue-500 shadow-lg shadow-blue-900/50'
          }`}
        >
          {loading ? 'AI 分析運算中...' : '執行晨間掃描 (8:50 AM)'}
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Stock List */}
        <div className="lg:col-span-2 space-y-4">
