    sendLineMessage("⚠️ 系統執行發生錯誤，請檢查 Google Apps Script 日誌。");
  }
}

function fetchGeminiRecommendations() {
  var url = \`https://generativelanguage.googleapis.com/v1beta/models/\${MODEL_NAME}:generateContent?key=\${GEMINI_API_KEY}\`;

  var systemPrompt = \`
    角色設定：你是一位擁有20年經驗的資深台股分析師。
    任務：掃描當前台灣股市狀況，找出 10 支股價在 50 元以下，且你看漲的優質潛力股。
    格式：回傳純 JSON 陣列，不要有 Markdown 標記。
    Schema: [{ "symbol": string, "name": string, "currentPrice": number, "buyPoint": number, "reason": string }]
  \`;

  var payload = {
    contents: [{
      parts: [{
        text: "找出 10 支股價 < 50 TWD 的潛力股，分析技術面與基本面，給出建議買入點。"
      }]
    }],
    systemInstruction: {
      parts: [{ text: systemPrompt }]
    },
    generationConfig: {
      responseMimeType: "application/json"
    }
  };

  var options = {
    method: "post",
    contentType: "application/json",
    payload: JSON.stringify(payload),
    muteHttpExceptions: true
  };

  var response = UrlFetchApp.fetch(url, options);
  var responseCode = response.getResponseCode();
  var responseText = response.getContentText();

  if (responseCode !== 200) {
    throw new Error(\`Gemini API Error (\${responseCode}): \${responseText}\`);
  }

  var json = JSON.parse(responseText);
  var contentText = json.candidates?.[0]?.content?.parts?.[0]?.text;

  if (!contentText) return [];

  var cleanJson = contentText.replace(/\`\`\`json/g, "").replace(/\`\`\`/g, "").trim();
  return JSON.parse(cleanJson);
}

function getFuglePrice(symbol) {
   if (!FUGLE_API_KEY) return null;
   try {
     // Fugle Market Data API v1.0
     var url = "https://api.fugle.tw/marketdata/v1.0/stock/intraday/quote/" + symbol;
     var options = {
       "headers": { "X-API-KEY": FUGLE_API_KEY },
       "method": "get",
       "muteHttpExceptions": true
     };
     var response = UrlFetchApp.fetch(url, options);
     if (response.getResponseCode() !== 200) return null;

     var data = JSON.parse(response.getContentText());
     // Check lastTrade price or closePrice
     if (data.lastTrade && data.lastTrade.price) return data.lastTrade.price;
     if (data.closePrice) return data.closePrice;
     return null;
   } catch (e) {
     Logger.log("Fugle Fetch Error for " + symbol + ": " + e);
     return null;
   }
}

function sendLineMessage(message) {
  var url = "https://api.line.me/v2/bot/message/push";
  var options = {
    method: "post",
    headers: {
      "Content-Type": "application/json",
      "Authorization": "Bearer " + LINE_CHANNEL_TOKEN
    },
    payload: JSON.stringify({
      "to": LINE_USER_ID,
      "messages": [
        {
          "type": "text",
          "text": message
        }
      ]
    }),
    muteHttpExceptions: true
  };

  var response = UrlFetchApp.fetch(url, options);
  Logger.log("LINE API Response: " + response.getResponseCode());
}
`;

  const copyToClipboard = () => {
