import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AnalysisResult, RecommendedStock } from "../types";

const SYSTEM_INSTRUCTION = `
角色設定：
你是一位擁有20年經驗的資深台股分析師，專精於「短線波段」與「當沖隔日沖」操作。
你的分析必須具備高度的「實戰性」，你的客戶需要知道「今天」能不能買。

核心原則：
1. **買點必須合理**：建議的買入點 (Buy Point) 必須基於「當前價格」附近的技術支撐（如 MA5, MA10, MA20 或布林中軌）。嚴禁給出遠低於現價的「歷史低點」或「腰斬價」。
2. **操作建議明確**：必須給出 BUY_NOW (現價可買)、WAIT (等待回檔)、SELL (建議賣出) 或 WATCH (觀望)。
3. **拒絕幻想**：若分析的買點與現價差距過大 (>10%)，請將建議設為 WAIT，並說明需等待回檔至該點位。
`;

export const getGeminiClient = (apiKey: string) => {
  if (!apiKey) return null;
  return new GoogleGenAI({ apiKey });
};

export const analyzeSingleStock = async (
  apiKey: string,
  symbol: string,
  currentPrice: number
): Promise<AnalysisResult> => {
  const ai = getGeminiClient(apiKey);
  if (!ai) throw new Error("API Key is missing");

  // Schema for structured output
  const analysisSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      symbol: { type: Type.STRING },
      name: { type: Type.STRING },
      trend: { type: Type.STRING, enum: ['BULLISH', 'BEARISH', 'NEUTRAL'] },
      suggestion: { type: Type.STRING, enum: ['BUY_NOW', 'WAIT', 'SELL', 'WATCH'] },
      predictedHigh: { type: Type.NUMBER },
      predictedLow: { type: Type.NUMBER },
      buyPoint: { type: Type.NUMBER },
      sellPoint: { type: Type.NUMBER },
      analysisText: { type: Type.STRING },
      reasoning: { type: Type.STRING },
    },
    required: ["symbol", "trend", "suggestion", "predictedHigh", "predictedLow", "buyPoint", "sellPoint", "analysisText", "reasoning"],
  };

  const prompt = `
    請分析台股代號：${symbol}。
    **目前參考價格約為：${currentPrice}** (這是最重要的基準)。

    請進行以下分析：
    1. 判斷未來一個月的走勢方向。
    2. 設定「極短線」操作策略：
       - 如果目前價格 ${currentPrice} 已經接近你的買入點 (Buy Point)，suggestion 回傳 "BUY_NOW"。
       - 如果目前價格遠高於買入點，suggestion 回傳 "WAIT"。
       - 買入點 (Buy Point) 必須是 **${currentPrice} 附近** 的支撐位 (例如 -1% ~ -5% 範圍內)，絕對不要給出一個距離現價 20% 以上的點位，除非股價已經崩盤。
    3. 預測區間與停利停損。

    請以 JSON 格式回傳。
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
      },
    });

    const text = response.text || "{}";
    return JSON.parse(text) as AnalysisResult;
  } catch (e) {
    console.error("Gemini Analysis Error:", e);
    throw e;
  }
};

export const getDailyRecommendations = async (apiKey: string): Promise<RecommendedStock[]> => {
  const ai = getGeminiClient(apiKey);
  if (!ai) throw new Error("API Key is missing");

  const recommendSchema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        symbol: { type: Type.STRING },
        name: { type: Type.STRING },
        currentPrice: { type: Type.NUMBER },
        buyPoint: { type: Type.NUMBER },
        suggestion: { type: Type.STRING, enum: ['BUY_NOW', 'WAIT', 'WATCH'] },
        reason: { type: Type.STRING },
        type: { type: Type.STRING, enum: ['TECHNICAL', 'FUNDAMENTAL'] },
      },
      required: ["symbol", "name", "currentPrice", "buyPoint", "suggestion", "reason", "type"],
    },
  };

  const prompt = `
    請掃描當前台灣股市狀況（使用 Search Tool 獲取最新即時數據）。
    找出 10 支股價在 50 元以下，且你看漲的優質潛力股。

    **重要規則：**
    1. **價格準確性**：必須獲取今日最新股價。
    2. **買點合理性**：建議的「買入點 (buyPoint)」必須非常接近「現價 (currentPrice)」。
       - 如果現價是 40，買點若是 20，這完全沒有意義，請不要推薦這種股票。
       - 買點應該在現價的 -5% 以內。
    3. **建議狀態 (suggestion)**：
       - 若 (現價 <= 買點 * 1.02) -> 標記為 "BUY_NOW"。
       - 若 (現價 > 買點 * 1.02) -> 標記為 "WAIT"。

    請回傳一個包含 10 個物件的 JSON 陣列。
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: recommendSchema,
      },
    });

    const text = response.text || "[]";
    return JSON.parse(text) as RecommendedStock[];
  } catch (e) {
    console.error("Gemini Recommendation Error:", e);
    // Fallback Mock Data
    return ([
      { symbol: "2883", name: "開發金", currentPrice: 14.5, buyPoint: 14.2, suggestion: "BUY_NOW", reason: "KD低檔黃金交叉，股價淨值比低。", type: "FUNDAMENTAL" },
      { symbol: "2002", name: "中鋼", currentPrice: 24.8, buyPoint: 24.0, suggestion: "WAIT", reason: "W底型態完成，等待回測頸線。", type: "TECHNICAL" },
    ] as RecommendedStock[]);
  }
};

