const AnalysisView: React.FC<Props> = ({ apiKey }) => {
  const [stockSymbol, setStockSymbol] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState('');
  const [fugleKey, setFugleKey] = useState('');

  useEffect(() => {
    const saved = localStorage.getItem('twStockAppSettings');
    if (saved) {
      const parsed = JSON.parse(saved);
      setFugleKey(parsed.fugleKey || '');
    }
  }, []);

  const handleAnalyze = async () => {
    if (!stockSymbol) return;
    if (!apiKey) {
      setError('請先至「設定」輸入 Gemini API Key');
      return;
    }

    setLoading(true);
    setError('');
    setResult(null);

    try {
      let currentPrice = 0;

      // 1. Try to get real price from Fugle
      if (fugleKey) {
        const realPrice = await fetchFuglePrice(stockSymbol, fugleKey);
        if (realPrice) {
          currentPrice = realPrice;
        }
      }

      if (currentPrice === 0) {
         console.warn("No Fugle Key provided or fetch failed, using AI estimation.");
      }

      const analysis = await analyzeSingleStock(apiKey, stockSymbol, currentPrice);
      setResult(analysis);
    } catch (err: any) {
      setError(err.message || '分析失敗，請稍後再試');
    } finally {
      setLoading(false);
    }
  };

  const getSuggestionStyle = (s: string) => {
    switch(s) {
      case 'BUY_NOW': return 'bg-twRed text-white animate-pulse';
      case 'WAIT': return 'bg-yellow-600 text-white';
      case 'SELL': return 'bg-twGreen text-white';
      default: return 'bg-gray-600 text-gray-200';
    }
  };

  const getSuggestionText = (s: string) => {
     switch(s) {
      case 'BUY_NOW': return '🔥 立即進場';
      case 'WAIT': return '⏳ 等待回檔';
      case 'SELL': return '📉 建議賣出';
      default: return '👀 觀望';
    }
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="flex gap-4 mb-8">
        <input
          type="text"
          value={stockSymbol}
          onChange={(e) => setStockSymbol(e.target.value.toUpperCase())}
          placeholder="輸入股票代號 (如: 2330)"
          className="flex-1 bg-cardBg border border-gray-600 rounded-lg px-6 py-4 text-xl focus:outline-none focus:border-twRed"
          onKeyDown={(e) => e.key === 'Enter' && handleAnalyze()}
        />
        <button
          onClick={handleAnalyze}
          disabled={loading}
          className={`px-8 py-4 rounded-lg font-bold text-white text-lg transition-all ${
            loading ? 'bg-gray-600 cursor-not-allowed' : 'bg-twRed hover:bg-red-600 shadow-lg hover:shadow-red-900/50'
          }`}
        >
          {loading ? '分析中...' : '開始分析'}
        </button>
      </div>

      {!fugleKey && (
        <div className="text-yellow-500 text-sm mb-4 bg-yellow-900/20 p-2 rounded border border-yellow-700">
          ⚠️ 尚未設定 Fugle API Key，AI 將使用模擬或歷史股價進行分析，建議前往設定頁面填寫以獲得精確買點。
        </div>
      )}

      {error && (
        <div className="p-4 bg-red-900/30 border border-red-500 text-red-200 rounded-lg mb-6">
          {error}
        </div>
      )}

      {result && (
        <div className="animate-fade-in space-y-6">
          {/* Header Card */}
          <div className="bg-cardBg rounded-xl p-6 shadow-xl border-l-4 border-twRed">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
              <div>
                <h2 className="text-3xl font-bold text-white mb-2">{result.name} <span className="text-gray-400 text-xl">({result.symbol})</span></h2>
                <div className="flex flex-wrap items-center gap-3">
                  <span className={`px-4 py-1.5 rounded-full text-base font-bold shadow-lg ${getSuggestionStyle(result.suggestion)}`}>
                    {getSuggestionText(result.suggestion)}
                  </span>
                  <span className={`px-3 py-1 rounded text-sm font-bold border ${
                    result.trend === 'BULLISH' ? 'border-twRed text-twRed' : 
                    result.trend === 'BEARISH' ? 'border-twGreen text-twGreen' : 'border-gray-500 text-gray-400'
                  }`}>
                    {result.trend === 'BULLISH' ? '趨勢偏多' : result.trend === 'BEARISH' ? '趨勢偏空' : '趨勢盤整'}
                  </span>
                </div>
              </div>
              <div className="text-left md:text-right bg-darkBg/50 p-3 rounded-lg border border-gray-700">
                <p className="text-gray-400 text-xs uppercase tracking-wider">Target Range</p>
                <p className="text-xl font-mono font-bold">
                  L: <span className="text-twGreen">{result.predictedLow}</span> ~ H: <span className="text-twRed">{result.predictedHigh}</span>
                </p>
              </div>
            </div>

            <StockChart 
              currentPrice={(result.predictedHigh + result.predictedLow) / 2} // Visual approximation if real price unknown
              predictedHigh={result.predictedHigh}
              predictedLow={result.predictedLow}
              buyPoint={result.buyPoint}
              sellPoint={result.sellPoint}
            />
          </div>

          {/* Analysis Details */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-cardBg rounded-xl p-6 shadow-lg border border-gray-700">
              <h3 className="text-xl font-bold mb-4 text-blue-400 border-b border-gray-700 pb-2">操作策略</h3>
              <div className="space-y-6">
                <div className="flex justify-between items-center p-3 bg-darkBg rounded border border-gray-800">
                  <span className="text-gray-400">建議買入點 (Buy Point)</span>
                  <div className="text-right">
                    <span className="text-2xl font-bold text-twRed">{result.buyPoint}</span>
                    <p className="text-xs text-gray-500">
                       {result.suggestion === 'WAIT' ? '需等待回檔' : '現價可嘗試'}
                    </p>
                  </div>
                </div>
                <div className="flex justify-between items-center p-3 bg-darkBg rounded border border-gray-800">
                  <span className="text-gray-400">建議停利點 (Sell Point)</span>
                  <span className="text-xl font-bold text-green-400">{result.sellPoint}</span>
                </div>
                <div className="mt-4">
                   <h4 className="text-sm text-gray-400 mb-2">策略理由：</h4>
                   <p className="text-gray-300 leading-relaxed text-sm bg-darkBg/30 p-3 rounded border-l-2 border-blue-500">
                     {result.reasoning}
                   </p>
                </div>
              </div>
            </div>

            <div className="bg-cardBg rounded-xl p-6 shadow-lg border border-gray-700">
              <h3 className="text-xl font-bold mb-4 text-purple-400 border-b border-gray-700 pb-2">AI 分析師觀點</h3>
              <p className="text-gray-300 leading-relaxed whitespace-pre-line text-base">
                {result.analysisText}
              </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AnalysisView;

import React from 'react';
import { AppSettings } from '../types';

interface Props {
  settings: AppSettings;
}

const GasGenerator: React.FC<Props> = ({ settings }) => {
  const hasKeys = settings.geminiKey && settings.lineChannelToken && settings.lineUserId;

  const gasCode = `
/**
 * 台灣股市 AI 分析師 - 自動化腳本 (2026 Messaging API + Fugle Smart Check)
 * 請將此代碼複製到 Google Apps Script (https://script.google.com/)
 */

// --- 設定區 ---
const GEMINI_API_KEY = "${settings.geminiKey || '請填入您的 Gemini API Key'}";
const LINE_CHANNEL_TOKEN = "${settings.lineChannelToken || '請填入 LINE Channel Access Token'}";
const LINE_USER_ID = "${settings.lineUserId || '請填入您的 LINE User ID'}";
const FUGLE_API_KEY = "${settings.fugleKey || ''}"; 
const MODEL_NAME = "gemini-3-flash-preview";

// --- 主程式：請設定「觸發條件」每天早上 8:50 執行此函式 ---
function dailyStockScan() {
  Logger.log("開始執行晨間掃描...");

  try {
    // 1. 呼叫 Gemini 分析股票
    var recommendations = fetchGeminiRecommendations();

    if (!recommendations || recommendations.length === 0) {
      Logger.log("未找到推薦股票或分析失敗");
      return;
    }

    // 2. 透過 Fugle API 更新即時股價並「重新驗證買點」
    if (FUGLE_API_KEY) {
      Logger.log("正在透過 Fugle API 更新股價並驗證策略...");
      recommendations = recommendations.map(function(stock) {
        var realPrice = getFuglePrice(stock.symbol);

        if (realPrice) {
          stock.currentPrice = realPrice;

          // 計算乖離率：(現價 - 買點) / 買點
          var gap = (stock.currentPrice - stock.buyPoint) / stock.buyPoint;

          // 自動修正建議狀態
          if (stock.currentPrice <= stock.buyPoint * 1.02) {
             // 現價小於等於 (買點+2%) -> 可買
             stock.suggestion = "BUY_NOW"; 
          } else {
             // 現價高出買點太多 -> 等待
             stock.suggestion = "WAIT";
             // 若差距過大 (例如 AI 說買 25，現價 90)，這代表 AI 幻覺，需標記異常
             if (gap > 0.2) {
                stock.suggestion = "DATA_ERROR"; // 標記為異常資料
                stock.reason = "⚠️ 買點與現價乖離過大，建議略過 (" + stock.buyPoint + " vs " + stock.currentPrice + ")";
             }
          }
        }
        return stock;
      });
    }

    // 過濾掉嚴重異常的數據
    var validRecommendations = recommendations.filter(function(s) {
      return s.suggestion !== "DATA_ERROR";
    });

    if (validRecommendations.length === 0) {
       sendLineMessage("⚠️ 今日 AI 掃描結果經 Fugle 驗證後，無符合邏輯之標的 (股價乖離過大)。");
       return;
    }

    // 3. 格式化訊息
    var message = "【早安！AI 實戰選股】\\n";
    message += "--------------------------------\\n";

    validRecommendations.forEach(function(stock, index) {
      // 根據狀態加上 Emoji
      var statusIcon = "👀";
      if (stock.suggestion === "BUY_NOW") statusIcon = "🔥 立即進場";
      if (stock.suggestion === "WAIT") statusIcon = "⏳ 等待回檔";

      message += \`\${index + 1}. \${stock.name} (\${stock.symbol}) \${statusIcon}\\n\`;
      message += \`   現價: \${stock.currentPrice} | 建議買點: \${stock.buyPoint}\\n\`;
      message += \`   理由: \${stock.reason}\\n\`;
      message += "--------------------------------\\n";
    });

    message += "\\n詳細技術線圖請查看儀表板。";

    // 4. 發送 LINE Message
    sendLineMessage(message);

  } catch (e) {
    Logger.log("發生錯誤: " + e.toString());
    sendLineMessage("⚠️ 系統執行發生錯誤: " + e.toString());
  }
}

function fetchGeminiRecommendations() {
  var url = \`https://generativelanguage.googleapis.com/v1beta/models/\${MODEL_NAME}:generateContent?key=\${GEMINI_API_KEY}\`;

  var systemPrompt = \`
    角色設定：你是一位實戰派台股分析師。
    任務：找出 10 支股價 < 50 TWD 的潛力股。
    **關鍵要求**：
    1. 「建議買點」必須是「今日可操作」的點位（例如昨日收盤價附近的支撐）。
    2. 嚴禁給出遠低於現價的買點（例如現價 40，買點卻給 20，這是錯誤的）。
    3. 如果現價偏高，買點最多只能低於現價 5%。
    格式：JSON 陣列。
    Schema: [{ "symbol": string, "name": string, "currentPrice": number, "buyPoint": number, "suggestion": string, "reason": string }]
    suggestion enum: ["BUY_NOW", "WAIT"]
  \`;

  var payload = {
    contents: [{
      parts: [{
        text: "找出 10 支股價 < 50 TWD 的潛力股，分析技術面，給出「貼近現價」的買入點。"
      }]
    }],
    systemInstruction: {
      parts: [{ text: systemPrompt }]
    },
    generationConfig: {
      responseMimeType: "application/json"
    }
  };

  var options = {
    method: "post",
    contentType: "application/json",
    payload: JSON.stringify(payload),
    muteHttpExceptions: true
  };

  var response = UrlFetchApp.fetch(url, options);
  if (response.getResponseCode() !== 200) {
    throw new Error("Gemini API Error: " + response.getContentText());
  }

  var json = JSON.parse(response.getContentText());
  var contentText = json.candidates?.[0]?.content?.parts?.[0]?.text;

  if (!contentText) return [];

  var cleanJson = contentText.replace(/\`\`\`json/g, "").replace(/\`\`\`/g, "").trim();
  return JSON.parse(cleanJson);
}

function getFuglePrice(symbol) {
   if (!FUGLE_API_KEY) return null;
   try {
     var url = "https://api.fugle.tw/marketdata/v1.0/stock/intraday/quote/" + symbol;
     var options = {
       "headers": { "X-API-KEY": FUGLE_API_KEY },
       "method": "get",
       "muteHttpExceptions": true
     };
     var response = UrlFetchApp.fetch(url, options);
     if (response.getResponseCode() !== 200) return null;

     var data = JSON.parse(response.getContentText());
     if (data.lastTrade && data.lastTrade.price) return data.lastTrade.price;
     if (data.closePrice) return data.closePrice;
     return null;
   } catch (e) {
     return null;
   }
}

function sendLineMessage(message) {
  var url = "https://api.line.me/v2/bot/message/push";
  var options = {
    method: "post",
    headers: {
      "Content-Type": "application/json",
      "Authorization": "Bearer " + LINE_CHANNEL_TOKEN
    },
    payload: JSON.stringify({
      "to": LINE_USER_ID,
      "messages": [
        {
          "type": "text",
          "text": message
        }
      ]
    }),
    muteHttpExceptions: true
  };

  UrlFetchApp.fetch(url, options);
}
`;

  const copyToClipboard = () => {
    navigator.clipboard.writeText(gasCode).then(() => {
      alert("程式碼已複製到剪貼簿！");
    });
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-cardBg rounded-xl p-6 shadow-xl border-l-4 border-purple-500">
        <h2 className="text-2xl font-bold text-white mb-2">Google Apps Script 自動化整合 (智慧驗證版)</h2>
        <p className="text-gray-400">
          此版本新增了「智慧驗證」邏輯：當 GAS 取得 Fugle 真實股價後，會自動計算買點乖離率。
          <br/>
          若現價高於買點太多，系統會自動將建議改為 <strong>「⏳ 等待回檔」</strong>，避免盲目追高或等待不切實際的低點。
        </p>
      </div>

      {!hasKeys ? (
        <div className="bg-yellow-900/30 border border-yellow-600 p-4 rounded-lg text-yellow-200">
          ⚠️ 請先至「設定」頁面填寫完整資訊 (Gemini Key, Line Token, Fugle Key)，系統將自動生成專屬程式碼。
        </div>
      ) : (
        <div className="bg-darkBg border border-gray-700 rounded-xl overflow-hidden">
          <div className="flex justify-between items-center bg-gray-800 px-4 py-2 border-b border-gray-700">
            <span className="text-sm text-gray-400 font-mono">Code.gs</span>
            <button 
              onClick={copyToClipboard}
              className="text-xs bg-purple-600 hover:bg-purple-500 text-white px-3 py-1.5 rounded transition-colors"
            >
              複製程式碼
            </button>
          </div>
          <pre className="p-4 overflow-x-auto text-sm font-mono text-green-400 leading-relaxed custom-scrollbar">
            {gasCode}
          </pre>
        </div>
      )}

      <div className="bg-cardBg rounded-xl p-6 shadow-lg">
        <h3 className="text-xl font-bold text-white mb-4">設定教學步驟</h3>
        <ol className="list-decimal list-inside space-y-3 text-gray-300">
          <li>前往 <a href="https://script.google.com/" target="_blank" rel="noreferrer" className="text-blue-400 hover:underline">Google Apps Script</a> 並建立一個「新專案」。</li>
          <li>將上方生成的程式碼完整複製，並覆蓋編輯器中的內容。</li>
          <li>點擊上方工具列的「執行 (Run)」按鈕，測試執行 <code>dailyStockScan</code> 函式。</li>
          <li>確認您的手機 LINE 收到訊息，內容應包含「🔥 立即進場」或「⏳ 等待回檔」的明確指示。</li>
        </ol>
      </div>
    </div>
  );
};

export default GasGenerator;

import React, { useState, useEffect } from 'react';
import { RecommendedStock, AppSettings } from '../types';
import { getDailyRecommendations } from '../services/geminiService';
import { sendLineNotification } from '../services/lineService';
import { fetchFuglePrice } from '../services/fugleService';

interface Props {
  settings: AppSettings;
}

const Dashboard: React.FC<Props> = ({ settings }) => {
  const [stocks, setStocks] = useState<RecommendedStock[]>([]);
  const [loading, setLoading] = useState(false);
  const [scanTime, setScanTime] = useState<string | null>(null);
  const [monitoring, setMonitoring] = useState(false);
  const [logs, setLogs] = useState<string[]>([]);

  // Function to simulate price checking
  const checkPrices = async (currentStocks: RecommendedStock[]) => {
    if (!settings.lineChannelToken || !settings.lineUserId) {
      addLog("⚠️ 無 LINE 設定，無法發送通知");
      return;
    }

    addLog("🔍 監控中：檢查股價是否觸及買點...");

    // In a real app, this would be a loop or interval.
    // For demo, we check if any stock is marked as 'BUY_NOW'
    const actionableStock = currentStocks.find(s => s.suggestion === 'BUY_NOW');

    if (actionableStock) {
       const msg = `【觸發買點通知】\n股票：${actionableStock.name} (${actionableStock.symbol})\n現價：${actionableStock.currentPrice}\n建議買點：${actionableStock.buyPoint}\n狀態：🔥 立即進場`;
       addLog(`🚀 ${actionableStock.name} 符合進場條件，發送 LINE 通知...`);
       const sent = await sendLineNotification(settings.lineChannelToken, settings.lineUserId, msg);
       if (sent) addLog("✅ LINE 通知發送成功");
       else addLog("❌ LINE 通知發送失敗");
    } else {
       addLog("ℹ️ 目前無股票符合「立即進場」條件，持續監控中...");
    }
  };

  const addLog = (msg: string) => {
    setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);
  };

  const handleMorningScan = async () => {
    if (!settings.geminiKey) {
      alert("請先設定 Gemini API Key");
      return;
    }

    setLoading(true);
    setScanTime(null);
    setLogs([]); // Clear logs
    addLog("開始執行晨間掃描 (8:50 AM 模擬)...");

    try {
      // 1. Get Recommendations from Gemini (Discovery Phase)
      addLog("🤖 AI 正在掃描市場潛力股...");
      const recs = await getDailyRecommendations(settings.geminiKey);

      let finalStocks = recs;

      // 2. Refresh Prices using Fugle API if available (Validation Phase)
      if (settings.fugleKey) {
        addLog("📊 正在透過 Fugle API 更新即時股價並驗證買點...");
        const updatedStocks = await Promise.all(recs.map(async (stock) => {
          const realPrice = await fetchFuglePrice(stock.symbol, settings.fugleKey);
          if (realPrice) {
            // Re-evaluate suggestion based on real price
            let newSuggestion = stock.suggestion;
            if (realPrice <= stock.buyPoint * 1.02) {
                newSuggestion = 'BUY_NOW';
            } else {
                newSuggestion = 'WAIT';
            }

            return { ...stock, currentPrice: realPrice, suggestion: newSuggestion };
          }
          return stock;
        }));
        finalStocks = updatedStocks;
      } else {
        addLog("⚠️ 未設定 Fugle Key，顯示價格與建議可能非最新即時數據");
      }

      setStocks(finalStocks);
      setScanTime(new Date().toLocaleTimeString());
      addLog(`掃描完成，找到 ${finalStocks.length} 支潛力股`);

      // Auto start monitoring if we have results
      setMonitoring(true);

      // Simulate the check immediately for demo
      setTimeout(() => checkPrices(finalStocks), 2000);

    } catch (e) {
      console.error(e);
      addLog("❌ 掃描失敗");
      alert("掃描失敗，請檢查 API Key 或網路");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center bg-cardBg p-6 rounded-xl shadow-lg border-l-4 border-blue-500">
        <div>
          <h2 className="text-2xl font-bold text-white">市場掃描監控台</h2>
          <p className="text-gray-400 mt-1">
            自動分析股價小於 50 元的潛力股，並監控進場點。
            {scanTime && <span className="ml-2 text-green-400 text-sm">上次掃描: {scanTime}</span>}
          </p>
        </div>
        <button
          onClick={handleMorningScan}
          disabled={loading}
          className={`px-6 py-3 rounded-lg font-bold text-white transition-all ${
            loading ? 'bg-gray-600' : 'bg-blue-600 hover:bg-blue-500 shadow-lg shadow-blue-900/50'
          }`}
        >
          {loading ? 'AI 分析運算中...' : '執行晨間掃描 (8:50 AM)'}
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Stock List */}
        <div className="lg:col-span-2 space-y-4">
          <h3 className="text-xl font-bold text-gray-200 mb-2">今日推薦清單 (Top 10)</h3>
          {stocks.length === 0 && !loading && (
            <div className="text-center py-20 bg-cardBg rounded-xl border border-dashed border-gray-700 text-gray-500">
              尚未執行掃描，請點擊上方按鈕開始
            </div>
          )}

          {stocks.map((stock) => (
