import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AnalysisResult, RecommendedStock } from "../types";

const SYSTEM_INSTRUCTION = `
角色設定：
你是一位擁有20年經驗的資深台股操盤手，專精於「隔日沖」與「波段起漲點」佈局。
你的任務是在每日收盤後，找出技術面與籌碼面最完美的股票，供明日開盤操作。

核心分析邏輯 (五大佐證法)：
在推薦任何一支股票前，你必須嚴格檢核以下五點，缺一不可：
1. **K線型態 (K-Line)**：確認出現明確的反轉或攻擊訊號 (如：長紅棒突破、多頭吞噬、晨星)。
2. **均線架構 (MA)**：股價必須站上關鍵均線 (如：站穩 MA20 月線，或均線黃金交叉)。
3. **量能籌碼 (Volume)**：必須有成交量配合 (如：量增價漲) 或法人主力進駐跡象。
4. **基本面 (Fundamental)**：公司體質不差，或有營收成長題材。
5. **題材熱度 (Catalyst)**：符合當下市場主流資金流向 (如：AI、重電、軍工)。

買點原則：
*   **拒絕追高**：買點必須設定在「支撐位」或「開盤預估回檔點」。
*   **勝率優先**：只選擇上述五點都呈現正向的股票。
`;

export const getGeminiClient = (apiKey: string) => {
  if (!apiKey) return null;
  return new GoogleGenAI({ apiKey });
};

export const analyzeSingleStock = async (
  apiKey: string,
  symbol: string,
  currentPrice: number
): Promise<AnalysisResult> => {
  const ai = getGeminiClient(apiKey);
  if (!ai) throw new Error("API Key is missing");

  // Schema for structured output
  const analysisSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      symbol: { type: Type.STRING },
      name: { type: Type.STRING },
      trend: { type: Type.STRING, enum: ['BULLISH', 'BEARISH', 'NEUTRAL'] },
      suggestion: { type: Type.STRING, enum: ['BUY_NOW', 'WAIT', 'SELL', 'WATCH'] },
      predictedHigh: { type: Type.NUMBER },
      predictedLow: { type: Type.NUMBER },
      buyPoint: { type: Type.NUMBER },
      sellPoint: { type: Type.NUMBER },
      analysisText: { type: Type.STRING },
      reasoning: { type: Type.STRING },
    },
    required: ["symbol", "trend", "suggestion", "predictedHigh", "predictedLow", "buyPoint", "sellPoint", "analysisText", "reasoning"],
  };

  const prompt = `
    請分析台股代號：${symbol}。
    **目前參考價格約為：${currentPrice}**。

    請以「明日操作勝率」為核心進行分析：
    1. 檢視 K 線型態與均線乖離。
    2. 給出明確的操作建議 (BUY_NOW: 現價/開盤可進, WAIT: 等回檔)。
    3. 設定合理的停利停損區間。

    請以 JSON 格式回傳。
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
      },
    });

    const text = response.text || "{}";
    return JSON.parse(text) as AnalysisResult;
  } catch (e) {
    console.error("Gemini Analysis Error:", e);
    throw e;
  }
};

