          description: "List exactly 5 supporting evidences"
        },
        type: { type: Type.STRING, enum: ['TECHNICAL', 'FUNDAMENTAL'] },
      },
      required: ["symbol", "name", "currentPrice", "buyPoint", "takeProfitPoint", "stopLossPoint", "suggestion", "reason", "evidences", "type"],
    },
