}

const GasGenerator: React.FC<Props> = ({ settings }) => {
  const hasKeys = settings.geminiKey && settings.lineChannelToken && settings.lineUserId;

  const gasCode = `
/**
 * 台灣股市 AI 分析師 - 自動化腳本 (五大佐證 + 雙重止盈版)
 * 請將此代碼複製到 Google Apps Script (https://script.google.com/)
 */

// --- 設定區 ---
const GEMINI_API_KEY = "${settings.geminiKey || '請填入您的 Gemini API Key'}";
const LINE_CHANNEL_TOKEN = "${settings.lineChannelToken || '請填入 LINE Channel Access Token'}";
const LINE_USER_ID = "${settings.lineUserId || '請填入您的 LINE User ID'}";
const FUGLE_API_KEY = "${settings.fugleKey || ''}"; 
const MODEL_NAME = "gemini-3-pro-preview";

// --- 主程式：請設定「觸發條件」每日下午執行 ---
function dailyStockScan() {
  Logger.log("開始執行高勝率選股掃描...");

  try {
    // 1. 呼叫 Gemini 分析股票
    var recommendations = fetchGeminiRecommendations();

    if (!recommendations || recommendations.length === 0) {
      Logger.log("未找到推薦股票或分析失敗");
      return;
    }

    // 2. 透過 Fugle API 更新收盤價 (驗證用)
    if (FUGLE_API_KEY) {
      recommendations = recommendations.map(function(stock) {
        var realPrice = getFuglePrice(stock.symbol);
        if (realPrice) stock.currentPrice = realPrice;

        // 簡單判斷：若 AI 建議買點與現價差異不大，標記為可操作
        if (stock.currentPrice <= stock.buyPoint * 1.05) {
             stock.suggestion = "BUY_NOW"; 
        } else {
             stock.suggestion = "WAIT";
        }
        return stock;
      });
    }

    // 3. 格式化訊息 (詳細版)
    var message = "【🦅 盤後精選：五大佐證 + 雙重目標】\\n";
    message += "--------------------------------\\n";

    recommendations.forEach(function(stock, index) {
      var icon = stock.suggestion === "BUY_NOW" ? "🔥" : "⏳";
      var partialGain = ((stock.partialTakeProfit - stock.buyPoint) / stock.buyPoint * 100).toFixed(1);
      var finalGain = ((stock.finalTakeProfit - stock.buyPoint) / stock.buyPoint * 100).toFixed(1);

      message += \`\${index + 1}. \${stock.name} (\${stock.symbol}) \${icon}\\n\`;
      message += \`   💰 收盤: \${stock.currentPrice} | 買點: \${stock.buyPoint}\\n\`;
      message += \`   🎯 部分止盈: \${stock.partialTakeProfit} (+\${partialGain}%)\\n\`;
      message += \`   🚀 最終目標: \${stock.finalTakeProfit} (+\${finalGain}%)\\n\`;
      message += \`   🛑 嚴設止損: \${stock.stopLossPoint}\\n\`;

      message += "\\n   [五大佐證]\\n";
      if (stock.evidences && stock.evidences.length > 0) {
        // 列出所有 5 點佐證
        stock.evidences.forEach(function(ev) {
           message += \`   • \${ev}\\n\`;
        });
      } else {
           message += \`   (分析資料不足)\\n\`;
      }
      message += "--------------------------------\\n";
    });

    message += "\\n註：最終目標價乃根據潛力預估，務必分批操作。";

    // 4. 發送 LINE Message
    sendLineMessage(message);

  } catch (e) {
    Logger.log("發生錯誤: " + e.toString());
    sendLineMessage("⚠️ 系統執行發生錯誤: " + e.toString());
  }
}

function fetchGeminiRecommendations() {
  var url = \`https://generativelanguage.googleapis.com/v1beta/models/\${MODEL_NAME}:generateContent?key=\${GEMINI_API_KEY}\`;

  var systemPrompt = \`
    角色設定：你是一位極度重視風險與勝率的操盤手。
    任務：選出 10 支股價 < 50 TWD，符合「五大佐證」且獲利潛力 > 20% 的股票。
    **關鍵要求**：
    1. 必須提供「部分止盈」(partialTakeProfit) 與「最終目標」(finalTakeProfit > 20%) 兩個出場價。
    2. 必須提供嚴格的「止損點」(stopLossPoint)。
    3. 必須完整列出 [型態, 均線, 籌碼, 基本, 題材] 五點佐證。

    格式：JSON 陣列。
    Schema: [{ "symbol": string, "name": string, "currentPrice": number, "buyPoint": number, "partialTakeProfit": number, "finalTakeProfit": number, "stopLossPoint": number, "suggestion": string, "evidences": string[] }]
  \`;

  var payload = {
    contents: [{
      parts: [{
        text: "選出 10 支高勝率潛力股，嚴格執行五大佐證，並設定雙重獲利目標。"
      }]
    }],
    systemInstruction: {
      parts: [{ text: systemPrompt }]
    },
    tools: [{googleSearch: {}}],
    generationConfig: {
      responseMimeType: "application/json"
    }
  };

  var options = {
    method: "post",
    contentType: "application/json",
    payload: JSON.stringify(payload),
    muteHttpExceptions: true
  };

  var response = UrlFetchApp.fetch(url, options);
  if (response.getResponseCode() !== 200) {
    throw new Error("Gemini API Error: " + response.getContentText());
  }

  var json = JSON.parse(response.getContentText());
  var contentText = json.candidates?.[0]?.content?.parts?.[0]?.text;

  if (!contentText) return [];

  var cleanJson = contentText.replace(/\`\`\`json/g, "").replace(/\`\`\`/g, "").trim();
  return JSON.parse(cleanJson);
}

function getFuglePrice(symbol) {
   if (!FUGLE_API_KEY) return null;
   try {
     var url = "https://api.fugle.tw/marketdata/v1.0/stock/intraday/quote/" + symbol;
     var options = {
       "headers": { "X-API-KEY": FUGLE_API_KEY },
       "method": "get",
       "muteHttpExceptions": true
     };
     var response = UrlFetchApp.fetch(url, options);
     if (response.getResponseCode() !== 200) return null;

     var data = JSON.parse(response.getContentText());
     if (data.lastTrade && data.lastTrade.price) return data.lastTrade.price;
     if (data.closePrice) return data.closePrice;
     return null;
   } catch (e) {
     return null;
   }
}

function sendLineMessage(message) {
  var url = "https://api.line.me/v2/bot/message/push";
  var options = {
    method: "post",
    headers: {
      "Content-Type": "application/json",
      "Authorization": "Bearer " + LINE_CHANNEL_TOKEN
    },
    payload: JSON.stringify({
      "to": LINE_USER_ID,
      "messages": [
        {
          "type": "text",
          "text": message
        }
      ]
    }),
    muteHttpExceptions: true
  };

  UrlFetchApp.fetch(url, options);
}
`;

  const copyToClipboard = () => {
    navigator.clipboard.writeText(gasCode).then(() => {
      alert("程式碼已複製到剪貼簿！");
    });
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-cardBg rounded-xl p-6 shadow-xl border-l-4 border-purple-500">
        <h2 className="text-2xl font-bold text-white mb-2">Google Apps Script (五大佐證 + 雙重止盈版)</h2>
        <p className="text-gray-400">
          此自動化腳本已針對您的需求進行最終升級：
          <br />
          1. <strong>五大佐證回歸</strong>：通知中將完整呈現 AI 判斷的五個依據 (型態、均線等)，不再省略。
          <br />
          2. <strong>分批出場機制</strong>：自動計算「部分止盈點」與「最終目標價 (>20%)」，協助您執行分批獲利策略。
        </p>
      </div>

      {!hasKeys ? (
        <div className="bg-yellow-900/30 border border-yellow-600 p-4 rounded-lg text-yellow-200">
          ⚠️ 請先至「設定」頁面填寫完整資訊，系統將自動生成專屬程式碼。
        </div>
      ) : (
        <div className="bg-darkBg border border-gray-700 rounded-xl overflow-hidden">
          <div className="flex justify-between items-center bg-gray-800 px-4 py-2 border-b border-gray-700">
            <span className="text-sm text-gray-400 font-mono">Code.gs</span>
            <button 
              onClick={copyToClipboard}
              className="text-xs bg-purple-600 hover:bg-purple-500 text-white px-3 py-1.5 rounded transition-colors"
            >
              複製程式碼
            </button>
          </div>
          <pre className="p-4 overflow-x-auto text-sm font-mono text-green-400 leading-relaxed custom-scrollbar">
            {gasCode}
          </pre>
        </div>
      )}

      <div className="bg-cardBg rounded-xl p-6 shadow-lg">
        <h3 className="text-xl font-bold text-white mb-4">使用說明</h3>
        <ol className="list-decimal list-inside space-y-3 text-gray-300">
          <li>將程式碼更新至 Google Apps Script 專案。</li>
          <li>建議在每日下午 15:30 (盤後數據出來後) 自動執行。</li>
          <li>收到 LINE 通知時，請重點檢核「五大佐證」是否符合您的個人判斷，再參考「買點」掛單。</li>
        </ol>
      </div>
    </div>
  );
};

