function dailyStockScan() {
  Logger.log("開始執行資產翻倍計畫掃描...");

  try {
    // 1. 讀取用戶庫存
    var portfolio = getUserPortfolio();
    Logger.log("目前庫存: " + JSON.stringify(portfolio));

    // 2. 呼叫 Gemini 分析 (傳入庫存資料)
    var result = fetchGeminiStrategy(portfolio);

    if (!result) {
      Logger.log("分析失敗");
      return;
    }

    var recommendations = result.recommendations || [];
    var strategyAdvice = result.strategyAdvice || "無策略建議";

    // 3. 透過 Fugle API 驗證價格 (選擇性)
    if (FUGLE_API_KEY && recommendations.length > 0) {
       // ... (保留原有的 Fugle 驗證邏輯，略) ...
    }

    // 4. 格式化 LINE 訊息 (包含庫存診斷與新股推薦)
    var message = "【🦅 3個月本金翻倍計畫】\\n";
    message += "--------------------------------\\n";

    // Part A: 庫存診斷
    message += "📊 **庫存診斷 & 資金策略**\\n";
    message += strategyAdvice + "\\n";
    message += "--------------------------------\\n";

    // Part B: 10支 高勝率潛力股
    message += "🚀 **Top 10 翻倍潛力股**\\n";

    recommendations.forEach(function(stock, index) {
      var icon = stock.suggestion === "BUY_NOW" ? "🔥" : "⏳";
      var finalGain = ((stock.finalTakeProfit - stock.buyPoint) / stock.buyPoint * 100).toFixed(1);

      message += \`\${index + 1}. \${stock.name} (\${stock.symbol}) \${icon}\\n\`;
      message += \`   💰 收盤: \${stock.currentPrice} | 買點: \${stock.buyPoint}\\n\`;
      message += \`   🚀 目標: \${stock.finalTakeProfit} (+\${finalGain}%)\\n\`;
      message += \`   🛑 止損: \${stock.stopLossPoint}\\n\`;
      message += "--------------------------------\\n";
    });

    message += "\\n💡 導師建議：若庫存股效率低，請勇敢換股操作。";

    sendLineMessage(message);

  } catch (e) {
    Logger.log("發生錯誤: " + e.toString());
    sendLineMessage("⚠️ 系統執行發生錯誤: " + e.toString());
  }
}

function getUserPortfolio() {
  try {
    var sheet = SpreadsheetApp.openById(SPREADSHEET_ID).getSheetByName(SHEET_TAB_NAME);
    if (!sheet) {
      Logger.log("找不到分頁: " + SHEET_TAB_NAME);
      return [];
    }

    // 假設格式: A欄=代號, B欄=成本, C欄=股數 (第一列為標題)
    var lastRow = sheet.getLastRow();
    if (lastRow <= 1) return [];

    var data = sheet.getRange(2, 1, lastRow - 1, 3).getValues();
    var portfolio = [];

    for (var i = 0; i < data.length; i++) {
      if (data[i][0]) {
        portfolio.push({
          symbol: data[i][0].toString(),
          cost: data[i][1],
          shares: data[i][2]
        });
      }
    }
    return portfolio;
  } catch (e) {
    Logger.log("讀取 Sheet 失敗: " + e.toString());
    return [];
  }
}

function fetchGeminiStrategy(portfolio) {
  var url = \`https://generativelanguage.googleapis.com/v1beta/models/\${MODEL_NAME}:generateContent?key=\${GEMINI_API_KEY}\`;

  var portfolioStr = JSON.stringify(portfolio);

  var systemPrompt = \`
    角色：你是一位「資產翻倍導師」。
    用戶情境：本金 2萬 TWD，目標 3個月翻倍至 4萬。已持有庫存：\${portfolioStr}。

    任務：
    1. **庫存診斷**：請搜尋庫存股的「今日收盤價」，計算目前盈虧。若該股趨勢不明或牛皮(波動小)，請明確建議「賣出換股」以提高資金效率。若趨勢好，建議「續抱」或「加碼」。
    2. **選股推薦**：選出 10 支股價 < 50，勝率極高且具備 >20% 獲利空間的股票。嚴格執行五大佐證。
    3. **價格驗證**：所有價格必須來自 Google Search 工具。

    回傳格式 (JSON Object)：
    {
      "strategyAdvice": "針對庫存的具體操作建議，例如：'目前持有 2330 獲利 5%，但考量翻倍目標，建議獲利了結，轉進波動更大的...'",
      "recommendations": [Array of Stocks as defined before]
    }
  \`;

  var payload = {
    contents: [{
      parts: [{
        text: "請分析我的庫存並給出翻倍策略，同時推薦 10 支高勝率潛力股。"
      }]
    }],
    systemInstruction: {
      parts: [{ text: systemPrompt }]
    },
    tools: [{googleSearch: {}}],
    generationConfig: {
      responseMimeType: "application/json"
    }
  };

  var options = {
    method: "post",
    contentType: "application/json",
    payload: JSON.stringify(payload),
    muteHttpExceptions: true
  };

  var response = UrlFetchApp.fetch(url, options);
  if (response.getResponseCode() !== 200) {
    throw new Error("Gemini API Error: " + response.getContentText());
  }

  var json = JSON.parse(response.getContentText());
  var contentText = json.candidates?.[0]?.content?.parts?.[0]?.text;

  if (!contentText) return null;

  var cleanJson = contentText.replace(/\`\`\`json/g, "").replace(/\`\`\`/g, "").trim();
  return JSON.parse(cleanJson);
}

