    muteHttpExceptions: true
  };

  try {
    var response = UrlFetchApp.fetch(url, options);
    var responseCode = response.getResponseCode();
    var responseText = response.getContentText();

    if (responseCode !== 200) {
      Logger.log("Gemini API Error (" + responseCode + "): " + responseText);
      return null;
    }

    var json = JSON.parse(responseText);
    var contentText = json.candidates?.[0]?.content?.parts?.[0]?.text;

    if (!contentText) {
      Logger.log("Empty Response from Gemini");
      return null;
    }

    return JSON.parse(contentText);
  } catch (e) {
    Logger.log("Fetch/Parse Error: " + e.toString());
    return null;
  }
}

function sendLineMessage(message) {
  var url = "https://api.line.me/v2/bot/message/push";
  var options = {
    method: "post",
    headers: {
      "Content-Type": "application/json",
      "Authorization": "Bearer " + LINE_CHANNEL_TOKEN
    },
    payload: JSON.stringify({
      "to": LINE_USER_ID,
      "messages": [
        {
          "type": "text",
          "text": message
        }
      ]
    }),
    muteHttpExceptions: true
  };

  try {
    var resp = UrlFetchApp.fetch(url, options);
    Logger.log("Line Response: " + resp.getResponseCode());
  } catch(e) {
    Logger.log("Line Send Error: " + e.toString());
  }
}
