// 透過 Fugle API 獲取即時股價 (最準確)
function getFuglePrice(symbol) {
  var url = "https://api.fugle.tw/marketdata/v1.0/stock/intraday/quote/" + symbol;
  var options = {
    "method": "get",
    "headers": {
      "X-API-KEY": FUGLE_API_KEY
    },
    "muteHttpExceptions": true
  };

  try {
    var response = UrlFetchApp.fetch(url, options);
    if (response.getResponseCode() == 200) {
      var data = JSON.parse(response.getContentText());
      // 優先使用最後成交價，若無則使用參考價或收盤價
      if (data.lastTrade && data.lastTrade.price) {
        return data.lastTrade.price;
      }
      if (data.closePrice) {
        return data.closePrice;
      }
    } else {
      Logger.log("Fugle API Error for " + symbol + ": " + response.getContentText());
    }
  } catch (e) {
    Logger.log("Fetch Fugle Error: " + e.toString());
  }
  return null;
}

function getUserPortfolio() {
  try {
    var sheet = SpreadsheetApp.openById(SPREADSHEET_ID).getSheetByName(SHEET_TAB_NAME);
    if (!sheet) {
      Logger.log("找不到分頁: " + SHEET_TAB_NAME);
      return [];
    }

    var lastRow = sheet.getLastRow();
    if (lastRow <= 1) return [];

    // 假設格式: A欄=代號, B欄=成本, C欄=股數
    var data = sheet.getRange(2, 1, lastRow - 1, 3).getValues();
    var portfolio = [];

    for (var i = 0; i < data.length; i++) {
      if (data[i][0]) {
        portfolio.push({
          symbol: data[i][0].toString(),
          cost: data[i][1],
          shares: data[i][2]
        });
      }
    }
    return portfolio;
  } catch (e) {
    Logger.log("讀取 Sheet 失敗: " + e.toString());
    return [];
  }
}

