// 讀取 Sheet 資料
function getUserPortfolio() {
  try {
    var sheet = SpreadsheetApp.openById(SPREADSHEET_ID).getSheetByName(SHEET_TAB_NAME);
    if (!sheet) return [];

    var lastRow = sheet.getLastRow();
    if (lastRow <= 1) return [];

    // 假設格式: Row 1=Header, Row 2+=Data
    // A欄: 代號, B欄: 成本, C欄: 股數
    var data = sheet.getRange(2, 1, lastRow - 1, 3).getValues();
    var portfolio = [];

    for (var i = 0; i < data.length; i++) {
      if (data[i][0]) {
        portfolio.push({
          symbol: data[i][0].toString(),
          cost: data[i][1],
          shares: data[i][2],
          currentPrice: 0 // 待填入
        });
      }
    }
    return portfolio;
  } catch (e) {
    Logger.log("讀取 Sheet 失敗: " + e.toString());
    return [];
  }
}

// AI 分析庫存策略 (重點功能)
function analyzePortfolioStrategy(portfolio) {
  var url = \`https://generativelanguage.googleapis.com/v1beta/models/\${MODEL_NAME}:generateContent?key=\${GEMINI_API_KEY}\`;

  var portfolioStr = JSON.stringify(portfolio);

  var systemPrompt = \`
    角色：你是一位嚴格的風險控管經理。
    任務：分析用戶的庫存股票，並給出具體的「停損」與「停利」建議。
    庫存資料 (包含成本與現價)：\${portfolioStr}

    請針對每一支股票生成一段簡短的純文字報告，格式如下：

    ● 股名 (代號)
      現價/成本：[現價] / [成本]
      狀態：[獲利/虧損 %]
      建議：[續抱/減碼/停損/加碼]
      🛑 停損價：[具體價格，若跌破此價必須離場]
      🎯 停利目標：[具體價格，建議分批出場點]

    請直接輸出組裝好的文字，不需要 JSON。語氣要專業、果斷。
  \`;

  var payload = {
    contents: [{ parts: [{ text: "請分析我的庫存，告訴我何時該跑，何時該賣。" }] }],
    systemInstruction: { parts: [{ text: systemPrompt }] },
    generationConfig: { responseMimeType: "text/plain" }
  };

  var options = {
    method: "post",
    contentType: "application/json",
    payload: JSON.stringify(payload),
    muteHttpExceptions: true
  };

  try {
    var response = UrlFetchApp.fetch(url, options);
    var json = JSON.parse(response.getContentText());
    return json.candidates?.[0]?.content?.parts?.[0]?.text || "無法生成庫存建議";
  } catch (e) {
    return "分析庫存時發生錯誤: " + e.toString();
  }
}

// AI 選股推薦 (維持原有機制)
function fetchGeminiRecommendations() {
  var url = \`https://generativelanguage.googleapis.com/v1beta/models/\${MODEL_NAME}:generateContent?key=\${GEMINI_API_KEY}\`;

  var systemPrompt = \`
    任務：選出 5 支台股潛力股 (股價 < 100)。
    規則：
    1. **必須使用 Google Search 查詢今日收盤價**。
    2. 必須符合 [型態, 籌碼, 題材] 優勢。
    3. 計算買點、停損點、獲利點。
  \`;

  var schema = {
    type: "ARRAY",
    items: {
      type: "OBJECT",
      properties: {
        symbol: { type: "STRING" },
        name: { type: "STRING" },
        currentPrice: { type: "NUMBER" },
        buyPoint: { type: "NUMBER" },
        finalTakeProfit: { type: "NUMBER" },
        stopLossPoint: { type: "NUMBER" },
        suggestion: { type: "STRING", enum: ["BUY_NOW", "WAIT"] }
      },
      required: ["symbol", "name", "currentPrice", "buyPoint", "finalTakeProfit", "stopLossPoint", "suggestion"]
    }
  };

  var payload = {
    contents: [{ parts: [{ text: "請搜尋今日最新股價，推薦 5 支高勝率股票。" }] }],
    systemInstruction: { parts: [{ text: systemPrompt }] },
    tools: [{googleSearch: {}}],
    generationConfig: { responseMimeType: "application/json", responseSchema: schema }
  };

  try {
    var response = UrlFetchApp.fetch(url, {
      method: "post",
      contentType: "application/json",
      payload: JSON.stringify(payload),
      muteHttpExceptions: true
    });
    var json = JSON.parse(response.getContentText());
    var text = json.candidates?.[0]?.content?.parts?.[0]?.text;
    return text ? JSON.parse(text) : [];
  } catch (e) {
    Logger.log("選股錯誤: " + e.toString());
    return [];
  }
}

// Fugle 查價
function getFuglePrice(symbol) {
  var url = "https://api.fugle.tw/marketdata/v1.0/stock/intraday/quote/" + symbol;
  try {
    var response = UrlFetchApp.fetch(url, {
      headers: { "X-API-KEY": FUGLE_API_KEY },
      muteHttpExceptions: true
    });
    if (response.getResponseCode() !== 200) return null;
    var data = JSON.parse(response.getContentText());
    if (data.lastTrade?.price) return data.lastTrade.price;
    if (data.closePrice) return data.closePrice;
    return null;
  } catch (e) { return null; }
}

