/**
 * Fetch real-time crypto price from Binance Public API
 * Documentation: https://binance-docs.github.io/apidocs/spot/en/#symbol-price-ticker
 */
export const fetchBinancePrice = async (symbol: string): Promise<number | null> => {
  if (!symbol) return null;

  // Clean symbol (remove slash if user typed BTC/USDT)
  const cleanSymbol = symbol.replace('/', '').toUpperCase();

  try {
    const url = `https://api.binance.com/api/v3/ticker/price?symbol=${cleanSymbol}`;

    const response = await fetch(url, {
      method: 'GET',
    });

    if (!response.ok) {
      console.warn(`Binance API Error: ${response.status} ${response.statusText}`);
      return null;
    }

    const data = await response.json();

    if (data && data.price) {
      return parseFloat(data.price);
    }

    return null;
  } catch (error) {
    console.error("Failed to fetch price from Binance:", error);
    return null;
  }
};

