import React, { useState, useEffect } from 'react';
import { RecommendedTarget, AppSettings } from '../types';
import { getDailyRecommendations } from '../services/geminiService';
import { sendLineNotification } from '../services/lineService';
import { fetchBinancePrice } from '../services/fugleService'; // Ensure this points to the file we renamed/updated content in

interface Props {
  settings: AppSettings;
}

const Dashboard: React.FC<Props> = ({ settings }) => {
  const [targets, setTargets] = useState<RecommendedTarget[]>([]);
  const [loading, setLoading] = useState(false);
  const [scanTime, setScanTime] = useState<string | null>(null);
  const [monitoring, setMonitoring] = useState(false);
  const [logs, setLogs] = useState<string[]>([]);

  const addLog = (msg: string) => {
    setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);
  };

  const checkPrices = async (currentTargets: RecommendedTarget[]) => {
    if (!settings.lineChannelToken || !settings.lineUserId) {
      addLog("⚠️ 無 LINE 設定，略過通知");
      return;
    }

    addLog("🔍 監控中：檢查幣價是否進入狙擊區...");

    // Simulate checking: In real app, this would be a loop or interval
    // For demo, we just check the first actionable target
    const actionable = currentTargets.find(s => s.suggestion === 'ENTER_NOW');

    if (actionable) {
       const direction = actionable.side === 'LONG' ? '🟢 做多' : '🔴 做空';
       const msg = `【🎯 狙擊訊號觸發】\n標的：${actionable.name} (${actionable.symbol})\n方向：${direction} (${actionable.leverage}x)\n現價：${actionable.currentPrice}\n進場：${actionable.entryPrice}\n止盈：${actionable.takeProfit}\n止損：${actionable.stopLoss}`;

       addLog(`🚀 ${actionable.symbol} 訊號觸發！發送 LINE 通知...`);
       const sent = await sendLineNotification(settings.lineChannelToken, settings.lineUserId, msg);
       if (sent) addLog("✅ LINE 通知已送出");
    }
  };

  const handleScan = async () => {
    if (!settings.geminiKey) {
      alert("請先設定 Gemini API Key");
      return;
    }

    setLoading(true);
    setScanTime(null);
    setLogs([]); 
    addLog("開始掃描幣安合約市場 (USDT-M Futures)...");

    try {
      // 1. Get Recommendations from Gemini
      addLog("🤖 AI 正在計算技術指標共振 (RSI, EMA, BB)...");
      const recs = await getDailyRecommendations(settings.geminiKey);

      let finalTargets = recs;

      // 2. Refresh Prices using Binance API
      addLog("📊 正在同步 Binance 即時報價...");
      const updatedTargets = await Promise.all(recs.map(async (target) => {
        const realPrice = await fetchBinancePrice(target.symbol);
        if (realPrice) {
          // Re-evaluate suggestion roughly based on entry price proximity (1% range)
          let newSuggestion = target.suggestion;
          const diff = Math.abs((realPrice - target.entryPrice) / target.entryPrice);

          if (diff < 0.01) {
              newSuggestion = 'ENTER_NOW'; 
          }

          return { ...target, currentPrice: realPrice, suggestion: newSuggestion };
        }
        return target;
      }));
      finalTargets = updatedTargets;

      setTargets(finalTargets);
      setScanTime(new Date().toLocaleTimeString());
      addLog(`掃描完成，鎖定 ${finalTargets.length} 個高盈虧比機會`);

      setMonitoring(true);
      setTimeout(() => checkPrices(finalTargets), 2000);

    } catch (e) {
      console.error(e);
      addLog("❌ 掃描失敗");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center bg-cardBg p-6 rounded-xl shadow-lg border-l-4 border-cryptoLong">
        <div>
          <h2 className="text-2xl font-bold text-white flex items-center gap-2">
            <span>🚀</span> 100u 翻倍計畫 (合約戰情室)
          </h2>
          <p className="text-gray-400 mt-1">
            目標：本金 100u → 1000u (10x)。策略：高盈虧比、5大指標共振、嚴格止損。
            {scanTime && <span className="ml-2 text-cryptoLong text-sm">Update: {scanTime}</span>}
          </p>
        </div>
        <button
          onClick={handleScan}
          disabled={loading}
          className={`px-6 py-3 rounded-lg font-bold text-white transition-all ${
            loading ? 'bg-gray-600' : 'bg-cryptoLong hover:bg-green-600 shadow-lg shadow-green-900/50'
          }`}
        >
          {loading ? 'AI 正在尋找獵物...' : '掃描合約市場'}
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Target List */}
        <div className="lg:col-span-2 space-y-4">
          <h3 className="text-xl font-bold text-gray-200 mb-2">狙擊清單 (Sniper List)</h3>
          {targets.length === 0 && !loading && (
            <div className="text-center py-20 bg-cardBg rounded-xl border border-dashed border-gray-700 text-gray-500">
              市場瞬息萬變，點擊按鈕讓 AI 幫你盯盤
            </div>
          )}

          {targets.map((target) => {
            const isLong = target.side === 'LONG';
            const sideColor = isLong ? 'text-cryptoLong' : 'text-cryptoShort';
            const sideBg = isLong ? 'bg-cryptoLong' : 'bg-cryptoShort';
            const borderColor = isLong ? 'border-cryptoLong' : 'border-cryptoShort';

            // Calculate R:R roughly
            const risk = Math.abs(target.entryPrice - target.stopLoss);
            const reward = Math.abs(target.takeProfit - target.entryPrice);
            const rrRatio = (reward / risk).toFixed(2);

            return (
              <div key={target.symbol} className={`bg-cardBg p-5 rounded-xl border border-gray-700 hover:${borderColor} transition-colors shadow-lg group`}>
                {/* Header */}
                <div className="flex flex-col md:flex-row justify-between items-start mb-4 gap-4">
                  <div className="flex items-center gap-4">
                    <div className={`w-14 h-14 rounded-full flex flex-col items-center justify-center font-bold text-white shadow-inner ${target.suggestion === 'ENTER_NOW' ? `${sideBg} animate-pulse` : 'bg-gray-700'}`}>
                      <span className="text-xs">{target.leverage}x</span>
                      <span className="text-sm">{target.side === 'LONG' ? '多' : '空'}</span>
                    </div>
                    <div>
                      <h4 className="font-bold text-xl text-white tracking-wide flex items-center gap-2">
                        {target.name} <span className="text-gray-400 text-base">({target.symbol})</span>
                      </h4>
                      <div className="flex gap-2 mt-1 text-sm text-gray-400">
                         現價: {target.currentPrice} | 進場: <span className="text-yellow-400 font-bold">{target.entryPrice}</span>
                      </div>
                    </div>
                  </div>

                  {/* Trade Setup Block */}
                  <div className="flex gap-2 w-full md:w-auto text-center">
                    <div className="bg-darkBg p-2 rounded border border-gray-700 flex-1 min-w-[80px]">
                       <div className="text-xs text-gray-400 mb-1">R:R Ratio</div>
                       <div className="text-lg font-bold text-yellow-500">1 : {rrRatio}</div>
                    </div>
                    <div className="bg-red-900/20 p-2 rounded border border-red-800 flex-1 min-w-[90px]">
                       <div className="text-xs text-red-400 mb-1">Stop Loss</div>
                       <div className="text-lg font-bold text-red-400">{target.stopLoss}</div>
                    </div>
                    <div className="bg-green-900/20 p-2 rounded border border-green-800 flex-1 min-w-[90px]">
                       <div className="text-xs text-green-400 mb-1">Take Profit</div>
                       <div className="text-lg font-bold text-green-400">{target.takeProfit}</div>
                    </div>
                  </div>
                </div>

                {/* 5 Indicators Evidences */}
                <div className="bg-darkBg/50 rounded-lg p-4 border border-gray-800">
                  <h5 className="text-xs font-bold text-gray-500 mb-3 uppercase tracking-wider border-b border-gray-800 pb-2 flex justify-between">
                    <span>五大共振指標 (Confirmation)</span>
                    <span className={sideColor}>{target.side} SIGNAL</span>
                  </h5>
                  <ul className="space-y-2">
                    {target.evidences && target.evidences.length > 0 ? (
                      target.evidences.map((evidence, idx) => (
                        <li key={idx} className="text-sm text-gray-300 flex items-start gap-2">
                          <span className={`${sideColor} mt-0.5 font-bold`}>✓</span>
                          <span className="leading-relaxed">{evidence}</span>
                        </li>
                      ))
                    ) : (
                      <li className="text-sm text-gray-500 italic">無詳細佐證資料</li>
                    )}
                  </ul>
                </div>
              </div>
            );
          })}
        </div>

        {/* System Log */}
        <div className="bg-cardBg p-4 rounded-xl border border-gray-700 h-[600px] flex flex-col">
          <h3 className="text-xl font-bold text-gray-200 mb-4 flex items-center gap-2">
            <span>📡</span> 監控日誌
            {monitoring && <span className="animate-pulse w-2 h-2 rounded-full bg-cryptoLong"></span>}
          </h3>
          <div className="flex-1 overflow-y-auto font-mono text-sm space-y-2 p-2 bg-darkBg rounded border border-gray-800">
            {logs.length === 0 ? (
              <span className="text-gray-600">等待指令...</span>
            ) : (
              logs.map((log, i) => (
                <div key={i} className="text-gray-300 border-b border-gray-800 pb-1 last:border-0">
                  {log}
                </div>
              ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { AppSettings } from '../types';

interface Props {
  settings: AppSettings;
  onSave: (s: AppSettings) => void;
}

const Settings: React.FC<Props> = ({ settings, onSave }) => {
  const [localSettings, setLocalSettings] = useState<AppSettings>(settings);
  const [showKey, setShowKey] = useState(false);

  useEffect(() => {
    setLocalSettings(settings);
  }, [settings]);

  const handleChange = (key: keyof AppSettings, value: string) => {
    setLocalSettings(prev => ({ ...prev, [key]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(localSettings);
    alert('設定已儲存！');
  };

  return (
    <div className="max-w-2xl mx-auto p-6 bg-cardBg rounded-xl shadow-lg border border-gray-700">
      <h2 className="text-2xl font-bold mb-6 text-cryptoLong">系統設定</h2>
      <form onSubmit={handleSubmit} className="space-y-6">

        <div>
          <label className="block text-sm font-medium text-gray-400 mb-1">Google Gemini API Key (必要)</label>
          <div className="relative">
            <input
              type={showKey ? "text" : "password"}
              value={localSettings.geminiKey}
              onChange={(e) => handleChange('geminiKey', e.target.value)}
              className="w-full bg-darkBg border border-gray-600 rounded px-4 py-2 focus:outline-none focus:border-cryptoLong transition-colors"
              placeholder="AI Studio API Key"
              required
            />
            <button
              type="button"
              onClick={() => setShowKey(!showKey)}
              className="absolute right-3 top-2 text-gray-500 hover:text-gray-300 text-sm"
            >
              {showKey ? "Hide" : "Show"}
            </button>
          </div>
          <p className="text-xs text-gray-500 mt-1">AI 核心，用於計算指標與分析策略。</p>
        </div>

        <div className="border-t border-gray-700 pt-6 mt-6">
            <h3 className="text-lg font-semibold text-white mb-4">LINE 通知設定</h3>
            <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-400 mb-1">Channel Access Token</label>
                  <input
                    type="password"
                    value={localSettings.lineChannelToken}
                    onChange={(e) => handleChange('lineChannelToken', e.target.value)}
                    className="w-full bg-darkBg border border-gray-600 rounded px-4 py-2 focus:outline-none focus:border-cryptoLong transition-colors"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-400 mb-1">User ID</label>
                  <input
                    type="text"
                    value={localSettings.lineUserId}
                    onChange={(e) => handleChange('lineUserId', e.target.value)}
                    className="w-full bg-darkBg border border-gray-600 rounded px-4 py-2 focus:outline-none focus:border-cryptoLong transition-colors"
                  />
                  <p className="text-xs text-gray-500 mt-1">
                      機器人將把狙擊訊號發送到此 ID。
                  </p>
                </div>
            </div>
        </div>

        <div className="border-t border-gray-700 pt-6 mt-6">
            <div>
              <label className="block text-sm font-medium text-gray-400 mb-1">Google Sheet ID (庫存監控)</label>
              <input
                type="text"
                value={localSettings.sheetId}
                onChange={(e) => handleChange('sheetId', e.target.value)}
                className="w-full bg-darkBg border border-gray-600 rounded px-4 py-2 focus:outline-none focus:border-cryptoLong transition-colors"
              />
              <p className="text-xs text-gray-500 mt-1">請填入您紀錄合約倉位的 Google Sheet ID。</p>
            </div>
        </div>

        <div className="pt-4">
          <button
            type="submit"
            className="w-full bg-cryptoLong hover:bg-green-600 text-white font-bold py-3 px-4 rounded transition-all transform hover:scale-[1.02]"
          >
            儲存設定
          </button>
        </div>
      </form>
    </div>
  );
};

export default Settings;

import React, { useState } from 'react';
import { AnalysisResult } from '../types';
import { analyzeSingleStock } from '../services/geminiService';
import { fetchBinancePrice } from '../services/fugleService'; // Ensure correct import
import StockChart from './StockChart';

interface Props {
  apiKey: string;
}

const AnalysisView: React.FC<Props> = ({ apiKey }) => {
  const [symbol, setSymbol] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState('');

  const handleAnalyze = async () => {
    if (!symbol) return;
    if (!apiKey) {
      setError('請先至「設定」輸入 Gemini API Key');
      return;
    }

    setLoading(true);
    setError('');
    setResult(null);

    try {
      let currentPrice = 0;

      // Get Real Price from Binance
      const realPrice = await fetchBinancePrice(symbol);
      if (realPrice) {
        currentPrice = realPrice;
      } else {
         console.warn("Binance fetch failed, AI will estimate.");
      }

      const analysis = await analyzeSingleStock(apiKey, symbol, currentPrice);
      setResult(analysis);
    } catch (err: any) {
      setError(err.message || '分析失敗，請檢查網路或 API Key');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="flex gap-4 mb-8">
        <input
          type="text"
          value={symbol}
          onChange={(e) => setSymbol(e.target.value.toUpperCase())}
          placeholder="輸入幣種 (如: BTCUSDT)"
          className="flex-1 bg-cardBg border border-gray-600 rounded-lg px-6 py-4 text-xl focus:outline-none focus:border-cryptoLong"
          onKeyDown={(e) => e.key === 'Enter' && handleAnalyze()}
        />
        <button
          onClick={handleAnalyze}
          disabled={loading}
          className={`px-8 py-4 rounded-lg font-bold text-white text-lg transition-all ${
            loading ? 'bg-gray-600 cursor-not-allowed' : 'bg-cryptoLong hover:bg-green-600 shadow-lg'
          }`}
        >
          {loading ? '分析中...' : 'AI 診斷'}
        </button>
      </div>

      {error && (
        <div className="p-4 bg-red-900/30 border border-red-500 text-red-200 rounded-lg mb-6">
          {error}
        </div>
      )}

      {result && (
        <div className="animate-fade-in space-y-6">
          {/* Header Card */}
          <div className={`bg-cardBg rounded-xl p-6 shadow-xl border-l-4 ${result.side === 'LONG' ? 'border-cryptoLong' : result.side === 'SHORT' ? 'border-cryptoShort' : 'border-gray-500'}`}>
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
              <div>
                <h2 className="text-3xl font-bold text-white mb-2">{result.name} <span className="text-gray-400 text-xl">({result.symbol})</span></h2>
                <div className="flex flex-wrap items-center gap-3">
                  <span className={`px-4 py-1.5 rounded-full text-base font-bold shadow-lg ${
                    result.side === 'LONG' ? 'bg-cryptoLong text-white' : 
                    result.side === 'SHORT' ? 'bg-cryptoShort text-white' : 'bg-gray-600'
                  }`}>
                    {result.side === 'LONG' ? '🟢 做多 (LONG)' : result.side === 'SHORT' ? '🔴 做空 (SHORT)' : '⚪ 觀望'}
                  </span>
                  <span className="px-3 py-1 rounded text-sm font-bold border border-yellow-500 text-yellow-500">
                    槓桿 {result.leverage}x
                  </span>
                </div>
              </div>
              <div className="text-left md:text-right bg-darkBg/50 p-3 rounded-lg border border-gray-700">
                <p className="text-gray-400 text-xs uppercase tracking-wider">Stop Loss / Take Profit</p>
                <p className="text-xl font-mono font-bold">
                  SL: <span className="text-red-400">{result.stopLoss}</span> / TP: <span className="text-green-400">{result.takeProfit}</span>
                </p>
              </div>
            </div>

            <StockChart 
              currentPrice={result.entryPoint} 
              predictedHigh={result.takeProfit} // Reusing props for visualization
              predictedLow={result.stopLoss}
              buyPoint={result.entryPoint}
              sellPoint={result.takeProfit}
            />
          </div>

          {/* Analysis Details */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-cardBg rounded-xl p-6 shadow-lg border border-gray-700">
              <h3 className="text-xl font-bold mb-4 text-blue-400 border-b border-gray-700 pb-2">交易策略 (Strategy)</h3>
              <div className="space-y-6">
                <div className="flex justify-between items-center p-3 bg-darkBg rounded border border-gray-800">
                  <span className="text-gray-400">進場點 (Entry)</span>
                  <span className="text-2xl font-bold text-yellow-400">{result.entryPoint}</span>
                </div>
                <div className="mt-4">
                   <h4 className="text-sm text-gray-400 mb-2">策略邏輯：</h4>
                   <p className="text-gray-300 leading-relaxed text-sm bg-darkBg/30 p-3 rounded border-l-2 border-blue-500">
                     {result.reasoning}
                   </p>
                </div>
              </div>
            </div>

