export const getGeminiClient = (apiKey: string) => {
  if (!apiKey) return null;
  return new GoogleGenAI({ apiKey });
};

export const analyzeSingleStock = async (
  apiKey: string,
  symbol: string,
  currentPrice: number
): Promise<AnalysisResult> => {
  const ai = getGeminiClient(apiKey);
  if (!ai) throw new Error("API Key is missing");

  const cleanSymbol = symbol.replace('/', '').toUpperCase();

  const analysisSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      symbol: { type: Type.STRING },
      name: { type: Type.STRING },
      trend: { type: Type.STRING, enum: ['BULLISH', 'BEARISH', 'NEUTRAL'] },
      side: { type: Type.STRING, enum: ['LONG', 'SHORT', 'WAIT'] },
      entryPoint: { type: Type.NUMBER },
      takeProfit: { type: Type.NUMBER },
      stopLoss: { type: Type.NUMBER },
      leverage: { type: Type.NUMBER, description: "Recommended leverage 5-20x" },
      analysisText: { type: Type.STRING },
      reasoning: { type: Type.STRING },
    },
    required: ["symbol", "trend", "side", "entryPoint", "takeProfit", "stopLoss", "leverage", "analysisText", "reasoning"],
  };

  const prompt = `
    請分析加密貨幣交易對：${cleanSymbol} (USDT-M Futures)。
    **目前市價約為：${currentPrice}**。

    請依照你的「五大指標」進行極短線合約分析。
    告訴我現在是該 Long、Short 還是空手觀望 (WAIT)？
    並給出高盈虧比 (R:R > 1:2) 的開倉點位建議。

    請以 JSON 格式回傳。
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
      },
    });

    const text = response.text || "{}";
    return JSON.parse(text) as AnalysisResult;
  } catch (e) {
    console.error("Gemini Analysis Error:", e);
    throw e;
  }
};

