// 模擬 FugleService 的 fetchTopActivePairs
function fetchBinanceTopMovers() {
  var url = "https://api.binance.com/api/v3/ticker/24hr";
  try {
    var response = UrlFetchApp.fetch(url);
    var allTickers = JSON.parse(response.getContentText());

    // Filter logic: Ends with USDT, Volume > 30M, Sort by Abs(Change)
    var filtered = allTickers.filter(function(t) {
      return t.symbol.endsWith("USDT") && 
             !t.symbol.includes("UP") && 
             !t.symbol.includes("DOWN") &&
             parseFloat(t.quoteVolume) > 30000000;
    });

    filtered.sort(function(a, b) {
      return Math.abs(parseFloat(b.priceChangePercent)) - Math.abs(parseFloat(a.priceChangePercent));
    });

    return filtered.slice(0, 15); // Top 15
  } catch (e) {
    Logger.log("Binance Scan Error: " + e);
    return [];
  }
}

function analyzeCandidatesWithAI(candidates) {
  var url = \`https://generativelanguage.googleapis.com/v1beta/models/\${MODEL_NAME}:generateContent?key=\${GEMINI_API_KEY}\`;

  var candidateInfo = candidates.map(function(c) {
    return c.symbol + " (Price: " + c.lastPrice + ", 24h%: " + c.priceChangePercent + "%)";
  }).join("\\n");

  var systemPrompt = \`
    任務：從提供的 Binance 熱門幣種清單中，挑選 3 個技術面最完美的合約交易機會。
    必須使用 Google Search 確認最新走勢。
    必須符合五大指標共振。
  \`;

  var schema = {
    type: "ARRAY",
    items: {
      type: "OBJECT",
      properties: {
        symbol: { type: "STRING" },
        currentPrice: { type: "NUMBER" },
        entryPrice: { type: "NUMBER" },
        takeProfit: { type: "NUMBER" },
        stopLoss: { type: "NUMBER" },
        side: { type: "STRING", enum: ["LONG", "SHORT"] },
        reason: { type: "STRING" }
      },
      required: ["symbol", "currentPrice", "entryPrice", "takeProfit", "stopLoss", "side", "reason"]
    }
  };

  var payload = {
    contents: [{ parts: [{ text: "候選清單：\\n" + candidateInfo }] }],
    systemInstruction: { parts: [{ text: systemPrompt }] },
    tools: [{googleSearch: {}}],
    generationConfig: { responseMimeType: "application/json", responseSchema: schema }
  };

  try {
    var response = UrlFetchApp.fetch(url, {
      method: "post",
      contentType: "application/json",
      payload: JSON.stringify(payload),
      muteHttpExceptions: true
    });

    var text = JSON.parse(response.getContentText()).candidates?.[0]?.content?.parts?.[0]?.text;
    if (!text) return [];

    // Clean markdown
    text = text.replace(/\\\`\\\`\\\`json/g, "").replace(/\\\`\\\`\\\`/g, "").trim();
    return JSON.parse(text);
  } catch (e) { 
    Logger.log("AI Analysis Error: " + e);
    return []; 
  }
}

function getUserPortfolio() {
  try {
    var ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    var sheet = ss.getSheetByName(SHEET_TAB_NAME) || ss.getSheets()[0];
    var lastRow = sheet.getLastRow();
    if (lastRow <= 1) return [];

    var data = sheet.getRange(2, 1, lastRow - 1, 4).getValues();
    var portfolio = [];

    for (var i = 0; i < data.length; i++) {
      if (data[i][0]) {
        portfolio.push({
          symbol: data[i][0].toString().trim().toUpperCase(),
          entryPrice: data[i][1],
          size: data[i][2],
          side: data[i][3],
          currentPrice: 0
        });
      }
    }
    return portfolio;
  } catch (e) { return []; }
}

function analyzePortfolioStrategy(portfolio) {
  var url = \`https://generativelanguage.googleapis.com/v1beta/models/\${MODEL_NAME}:generateContent?key=\${GEMINI_API_KEY}\`;

  var payload = {
    contents: [{ parts: [{ text: "分析我的持倉：" + JSON.stringify(portfolio) }] }],
    systemInstruction: { parts: [{ text: "給出平倉或續抱建議 (純文字)" }] },
    generationConfig: { responseMimeType: "text/plain" }
  };

  try {
    var response = UrlFetchApp.fetch(url, {
      method: "post",
      contentType: "application/json",
      payload: JSON.stringify(payload),
      muteHttpExceptions: true
    });
    return JSON.parse(response.getContentText()).candidates?.[0]?.content?.parts?.[0]?.text || "分析失敗";
  } catch (e) { return "分析錯誤"; }
}

function getBinancePrice(symbol) {
  var url = "https://api.binance.com/api/v3/ticker/price?symbol=" + symbol;
  try {
    var response = UrlFetchApp.fetch(url);
    var data = JSON.parse(response.getContentText());
    return parseFloat(data.price);
  } catch (e) { return null; }
}

function sendLineMessage(message) {
  UrlFetchApp.fetch("https://api.line.me/v2/bot/message/push", {
    method: "post",
    headers: {
      "Content-Type": "application/json",
      "Authorization": "Bearer " + LINE_CHANNEL_TOKEN
    },
    payload: JSON.stringify({
      "to": LINE_USER_ID,
      "messages": [{ "type": "text", "text": message }]
    }),
    muteHttpExceptions: true
  });
}
`;

  const copyToClipboard = () => {
    navigator.clipboard.writeText(gasCode).then(() => {
