  const addLog = (msg: string) => {
    setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);
  };

  const checkPrices = async (currentTargets: RecommendedTarget[]) => {
    if (!settings.lineChannelToken || !settings.lineUserId) {
      addLog("⚠️ 無 LINE 設定，略過通知");
      return;
    }

    addLog("🔍 監控中：檢查幣價是否進入狙擊區...");

    // Simulate checking: In real app, this would be a loop or interval
    // For demo, we just check the first actionable target
    const actionable = currentTargets.find(s => s.suggestion === 'ENTER_NOW');

    if (actionable) {
       const direction = actionable.side === 'LONG' ? '🟢 做多' : '🔴 做空';
       const msg = `【🎯 狙擊訊號觸發】\n標的：${actionable.name} (${actionable.symbol})\n方向：${direction} (${actionable.leverage}x)\n現價：${actionable.currentPrice}\n進場：${actionable.entryPrice}\n止盈：${actionable.takeProfit}\n止損：${actionable.stopLoss}`;

       addLog(`🚀 ${actionable.symbol} 訊號觸發！發送 LINE 通知...`);
       const sent = await sendLineNotification(settings.lineChannelToken, settings.lineUserId, msg);
       if (sent) addLog("✅ LINE 通知已送出");
    }
  };

  const handleScan = async () => {
    if (!settings.geminiKey) {
      alert("請先設定 Gemini API Key");
      return;
    }

    setLoading(true);
    setScanTime(null);
    setLogs([]); 
    addLog("🚀 啟動全市場掃描程序...");

    try {
      // 1. Scan Binance for Top Volatility
