      const updatedTargets = await Promise.all(recs.map(async (target) => {
        const realPrice = await fetchBinancePrice(target.symbol);
        if (realPrice) {
          let newSuggestion = target.suggestion;
          let newEntryPrice = target.entryPrice;
          let notes = "";

          // Smart Entry Logic:
          // If SHORT: Current Price > Entry Price is BETTER (Sell Higher). 
          // If LONG: Current Price < Entry Price is BETTER (Buy Lower).
          // In these cases, we update Entry Price to Real Price and trigger ENTER_NOW.

          if (target.side === 'SHORT') {
            if (realPrice > target.entryPrice) {
               newSuggestion = 'ENTER_NOW';
               newEntryPrice = realPrice; // Take the better price
               notes = "(價格優於預期，立即進場)";
            } else {
               // Normal check: within 0.5% range
               const diff = Math.abs((realPrice - target.entryPrice) / target.entryPrice);
               if (diff < 0.005) newSuggestion = 'ENTER_NOW';
            }
          } else if (target.side === 'LONG') {
            if (realPrice < target.entryPrice) {
               newSuggestion = 'ENTER_NOW';
               newEntryPrice = realPrice; // Take the better price
               notes = "(價格優於預期，立即進場)";
            } else {
               const diff = Math.abs((realPrice - target.entryPrice) / target.entryPrice);
               if (diff < 0.005) newSuggestion = 'ENTER_NOW';
            }
          }

          return { 
            ...target, 
            currentPrice: realPrice, 
            entryPrice: newEntryPrice,
            suggestion: newSuggestion,
            reason: notes ? `${notes} ${target.reason}` : target.reason
          };
        }
        return target;
      }));
      finalTargets = updatedTargets;

      setTargets(finalTargets);
      setScanTime(new Date().toLocaleTimeString());
      addLog(`🏁 分析完成！精選 ${finalTargets.length} 檔高勝率標的`);

      setMonitoring(true);
