/**
 * Helper function to handle CORS issues by falling back to a proxy if direct access fails.
 * Binance API often blocks direct browser requests due to CORS policies.
 */
const fetchWithFallback = async (url: string): Promise<Response> => {
  try {
    // 1. Attempt Direct Fetch
    const response = await fetch(url);
    if (!response.ok) throw new Error(`Direct fetch failed: ${response.status}`);
    return response;
  } catch (directError) {
    // 2. Fallback to Public CORS Proxy (api.allorigins.win)
    // This allows the app to work in localhost or static hosting environments without a backend.
    try {
      console.warn(`Direct fetch failed (CORS likely). Retrying via proxy: ${url}`);
      const proxyUrl = `https://api.allorigins.win/raw?url=${encodeURIComponent(url)}`;
      const proxyResponse = await fetch(proxyUrl);
      if (!proxyResponse.ok) throw new Error(`Proxy fetch failed: ${proxyResponse.status}`);
      return proxyResponse;
    } catch (proxyError) {
      // Throw the original error or the proxy error
      throw proxyError; 
    }
  }
};

/**
 * Fetch real-time crypto price from Binance Public API
 * Documentation: https://binance-docs.github.io/apidocs/spot/en/#symbol-price-ticker
 */
export const fetchBinancePrice = async (symbol: string): Promise<number | null> => {
  if (!symbol) return null;

  // Clean symbol (remove slash if user typed BTC/USDT)
  const cleanSymbol = symbol.replace('/', '').toUpperCase();

  try {
    const url = `https://api.binance.com/api/v3/ticker/price?symbol=${cleanSymbol}`;

    // Use the fallback fetcher
    const response = await fetchWithFallback(url);

    // Safely parse JSON to avoid "Unexpected end of input"
    const text = await response.text();
    if (!text) return null;

    const data = JSON.parse(text);

    if (data && data.price) {
      return parseFloat(data.price);
    }

    return null;
  } catch (error) {
    console.error("Failed to fetch price from Binance:", error);
    return null;
  }
};

/**
 * Scan ALL Binance USDT pairs to find high volume & high volatility candidates.
 * Rules:
 * 1. Must end with 'USDT'
 * 2. 24h Volume > 30M USDT (Liquidity check)
 * 3. Sort by absolute 24h change % (Volatility check)
 * 4. Return Top 15 candidates
 */
export const fetchTopActivePairs = async (): Promise<BinanceTicker[]> => {
  try {
    const url = `https://api.binance.com/api/v3/ticker/24hr`;

    // Use the fallback fetcher
    const response = await fetchWithFallback(url);

    const text = await response.text();
    if (!text) return [];

    const allTickers = JSON.parse(text) as BinanceTicker[];

    // Filter and Sort
    const topPairs = allTickers
      .filter(t => t.symbol.endsWith('USDT'))
      .filter(t => !t.symbol.includes('UP') && !t.symbol.includes('DOWN')) // Remove leveraged tokens
      .filter(t => !t.symbol.includes('USDC') && !t.symbol.includes('FDUSD')) // Remove Stablecoin pairs
      .filter(t => parseFloat(t.quoteVolume) > 30000000) // Volume > 30M USDT (Strict Discipline: Liquidity)
      .sort((a, b) => Math.abs(parseFloat(b.priceChangePercent)) - Math.abs(parseFloat(a.priceChangePercent))) // Sort by Volatility
      .slice(0, 15); // Take top 15

    return topPairs;
  } catch (error) {
    console.error("Failed to scan market:", error);
    return [];
  }
};

