import { AnalysisResult, RecommendedTarget, BinanceTicker } from "../types";

const SYSTEM_INSTRUCTION = `
角色設定：
你是一位擁有20年實戰經驗的資深台股與加密貨幣分析師。你精通所有技術分析流派，且只挑選「收益最高、勝率最高」的標的。
操作風格：「快、狠、準」，不做模稜兩可的預測。

**【語言要求】**
**所有回應必須使用「繁體中文 (Traditional Chinese)」**，語氣專業且果斷。

**【核心交易哲學】**
1.  **寧缺勿濫**：如果市場充滿雜訊，寧可空手。只推薦勝率超過 80% 的機會。
2.  **五大指標共振 (進場必須符合 5 項才動作)**：
    *   **K線型態 (Price Action)**：吞噬、Pinbar、假突破(2B法則)。
    *   **均線 (EMA)**：EMA 20/50/200 排列正確。
    *   **動能 (RSI/MACD)**：RSI 背離、MACD 柱狀圖轉折。
    *   **布林通道 (Bollinger Bands)**：擠壓後的爆發、觸碰軌道的逆勢單。
    *   **量能 (Volume)**：價量配合，突破必須帶量。

**【進場點位邏輯】**
1. **做空 (SHORT)**：Entry Price 必須 >= Current Price (反彈空)。若建議「市價進場」，Entry Price 設為市價。
2. **做多 (LONG)**：Entry Price 必須 <= Current Price (回調多)。若建議「市價進場」，Entry Price 設為市價。

**【數據要求】**
**務必使用 Google Search 獲取最新的「Binance 現貨或合約價格」。**
`;

export const getGeminiClient = (apiKey: string) => {
  if (!apiKey) return null;
  return new GoogleGenAI({ apiKey });
};

const cleanJsonText = (text: string): string => {
  if (!text) return "";
  let clean = text.replace(/```json/g, "").replace(/```/g, "").trim();
  return clean;
};

export const analyzeSingleStock = async (
  apiKey: string,
  symbol: string,
  currentPrice: number
): Promise<AnalysisResult> => {
  const ai = getGeminiClient(apiKey);
  if (!ai) throw new Error("API Key is missing");

  const cleanSymbol = symbol.replace('/', '').toUpperCase();

  const analysisSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      symbol: { type: Type.STRING },
      name: { type: Type.STRING },
      trend: { type: Type.STRING, enum: ['BULLISH', 'BEARISH', 'NEUTRAL'] },
      side: { type: Type.STRING, enum: ['LONG', 'SHORT', 'WAIT'] },
      entryPoint: { type: Type.NUMBER },
      takeProfit: { type: Type.NUMBER },
      stopLoss: { type: Type.NUMBER },
      leverage: { type: Type.NUMBER },
      analysisText: { type: Type.STRING },
      reasoning: { type: Type.STRING },
    },
    required: ["symbol", "trend", "side", "entryPoint", "takeProfit", "stopLoss", "leverage", "analysisText", "reasoning"],
  };

  const prompt = `
    請分析交易對：${cleanSymbol} (USDT-M Futures)。
    **目前市價約為：${currentPrice}**。

    請依照你的「五大指標」進行極短線分析。
    告訴我現在是該做多、做空還是觀望？
    請使用繁體中文回答。
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: analysisSchema,
      },
    });

    const rawText = response.text || "{}";
    const cleanText = cleanJsonText(rawText);
    if (!cleanText) return {} as AnalysisResult;
    return JSON.parse(cleanText) as AnalysisResult;
  } catch (e) {
    console.error("Gemini Analysis Error:", e);
    throw e;
  }
};

