  const [scanTime, setScanTime] = useState<string | null>(null);
  const [monitoring, setMonitoring] = useState(false);
  const [logs, setLogs] = useState<string[]>([]);

  const addLog = (msg: string) => {
    setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);
  };

  const checkPrices = async (currentTargets: RecommendedTarget[]) => {
    if (!settings.lineChannelToken || !settings.lineUserId) {
      addLog("⚠️ 無 LINE 設定，略過通知");
      return;
    }

    addLog("🔍 監控中：檢查幣價是否進入狙擊區...");

    const actionable = currentTargets.find(s => s.suggestion === 'ENTER_NOW');

