      const updatedTargets = await Promise.all(recs.map(async (target) => {
        const realPrice = await fetchBinancePrice(target.symbol);
        if (realPrice) {
          let newSuggestion = target.suggestion;
          let newEntryPrice = target.entryPrice;
          let notes = "";

          // Smart Entry Logic
          if (target.side === 'SHORT') {
            if (realPrice > target.entryPrice) {
               newSuggestion = 'ENTER_NOW';
               newEntryPrice = realPrice; 
               notes = "(價格優於預期)";
            } else {
               const diff = Math.abs((realPrice - target.entryPrice) / target.entryPrice);
               if (diff < 0.005) newSuggestion = 'ENTER_NOW';
            }
          } else if (target.side === 'LONG') {
            if (realPrice < target.entryPrice) {
               newSuggestion = 'ENTER_NOW';
               newEntryPrice = realPrice; 
               notes = "(價格優於預期)";
            } else {
               const diff = Math.abs((realPrice - target.entryPrice) / target.entryPrice);
               if (diff < 0.005) newSuggestion = 'ENTER_NOW';
            }
          }

          return { 
            ...target, 
            currentPrice: realPrice, 
            entryPrice: newEntryPrice,
            suggestion: newSuggestion,
            reason: notes ? `${notes} ${target.reason}` : target.reason
          };
        }
        return target;
      }));

      // 4. SORTING: Priority 1 = ENTER_NOW, Priority 2 = Highest WinRate
      updatedTargets.sort((a, b) => {
        // First check availability
        if (a.suggestion === 'ENTER_NOW' && b.suggestion !== 'ENTER_NOW') return -1;
        if (b.suggestion === 'ENTER_NOW' && a.suggestion !== 'ENTER_NOW') return 1;

        // Then check WinRate
        const winA = a.winRate || 0;
        const winB = b.winRate || 0;
        return winB - winA;
      });

      setTargets(updatedTargets);
      setScanTime(new Date().toLocaleTimeString());
      addLog(`🏁 分析完成！已將「勝率最高」且「可立即進場」的標的置頂`);

      setMonitoring(true);
      setTimeout(() => checkPrices(updatedTargets), 2000);

    } catch (e) {
      console.error(e);
      addLog("❌ 掃描失敗，請檢查 API Key 或網路連線");
    } finally {
      setLoading(false);
    }
