import React, { useState, useEffect } from 'react';
import { RecommendedTarget, AppSettings } from '../types';
import { getDailyRecommendations } from '../services/geminiService';
import { sendLineNotification } from '../services/lineService';
import { fetchBinancePrice, fetchTopActivePairs } from '../services/fugleService';

interface Props {
  settings: AppSettings;
}

const Dashboard: React.FC<Props> = ({ settings }) => {
  const [targets, setTargets] = useState<RecommendedTarget[]>([]);
  const [loading, setLoading] = useState(false);
  const [scanTime, setScanTime] = useState<string | null>(null);
  const [logs, setLogs] = useState<string[]>([]);

  const addLog = (msg: string) => {
    setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);
  };

  const handleScan = async () => {
    if (!settings.geminiKey) return alert("請先設定 Gemini API Key");

    setLoading(true);
    setScanTime(null);
    setLogs([]); 
    addLog("🚀 啟動「全市場型態+籌碼」深度掃描...");

    try {
      addLog("📡 正在抓取現貨成交量 & 波動數據...");
      const topCandidates = await fetchTopActivePairs();

      if (topCandidates.length === 0) {
        addLog("⚠️ 無法獲取幣安數據");
        setLoading(false);
        return;
      }

      addLog(`✅ 鎖定 ${topCandidates.length} 檔熱門幣種。正在注入合約持倉與 K 線數據...`);

      addLog("🧠 AI 正在識別形態 (W底/M頭) 並比對多空比情緒...");
      const recs = await getDailyRecommendations(settings.geminiKey, topCandidates);

      addLog("🎯 校準最新報價 & 策略優化...");
      const updatedTargets = await Promise.all(recs.map(async (target) => {
        const realPrice = await fetchBinancePrice(target.symbol);
        return { ...target, currentPrice: realPrice || target.currentPrice };
      }));

      updatedTargets.sort((a, b) => {
        if (a.suggestion === 'ENTER_NOW' && b.suggestion !== 'ENTER_NOW') return -1;
        if (b.suggestion === 'ENTER_NOW' && a.suggestion !== 'ENTER_NOW') return 1;
        return (b.winRate || 0) - (a.winRate || 0);
      });

      setTargets(updatedTargets);
      setScanTime(new Date().toLocaleTimeString());
