import { BinanceTicker, FuturesData } from "../types";

const fetchWithFallback = async (url: string): Promise<Response> => {
  try {
    const response = await fetch(url);
    if (!response.ok) throw new Error(`Direct fetch failed: ${response.status}`);
    return response;
  } catch (directError) {
    try {
      const proxyUrl = `https://api.allorigins.win/raw?url=${encodeURIComponent(url)}`;
      const proxyResponse = await fetch(proxyUrl);
      if (!proxyResponse.ok) throw new Error(`Proxy fetch failed: ${proxyResponse.status}`);
      return proxyResponse;
    } catch (proxyError) {
      throw proxyError; 
    }
  }
};

/**
 * Fetch Price with Dual-Source Strategy (Spot -> Futures Fallback)
 * Crucial for coins like HYPEUSDT which might only be listed on Futures.
 */
export const fetchBinancePrice = async (symbol: string): Promise<number | null> => {
  if (!symbol) return null;
  const cleanSymbol = symbol.replace('/', '').toUpperCase();

  // 1. Try Spot Market First
  try {
    const spotUrl = `https://api.binance.com/api/v3/ticker/price?symbol=${cleanSymbol}`;
    const response = await fetchWithFallback(spotUrl);
    const data = JSON.parse(await response.text());
    if (data && data.price) {
      return parseFloat(data.price);
    }
  } catch (spotError) {
    // console.warn(`Spot price not found for ${cleanSymbol}, trying Futures...`);
  }

  // 2. Fallback to Futures Market (USDT-M)
  try {
    const futuresUrl = `https://fapi.binance.com/fapi/v1/ticker/price?symbol=${cleanSymbol}`;
    const response = await fetchWithFallback(futuresUrl);
    const data = JSON.parse(await response.text());
    if (data && data.price) {
      // console.log(`Found Futures price for ${cleanSymbol}: ${data.price}`);
      return parseFloat(data.price);
    }
  } catch (futuresError) {
    console.error(`Failed to fetch price for ${cleanSymbol} from both Spot and Futures.`);
  }

  return null;
};

/**
 * Fetch K-Line Data with Dual-Source Strategy (Spot -> Futures Fallback)
 */
export const fetchKlines = async (symbol: string, interval: string = '4h', limit: number = 20): Promise<string> => {
  const cleanSymbol = symbol.replace('/', '').toUpperCase();

  const parseKlines = (data: any[]) => {
    // Format: Close prices only for pattern recognition
    return data.map((k: any) => parseFloat(k[4]).toFixed(4)).join(', ');
  };

  // 1. Try Spot K-Lines
  try {
    const spotUrl = `https://api.binance.com/api/v3/klines?symbol=${cleanSymbol}&interval=${interval}&limit=${limit}`;
    const response = await fetchWithFallback(spotUrl);
    const data = JSON.parse(await response.text());
    if (Array.isArray(data) && data.length > 0) {
      return parseKlines(data);
    }
  } catch (e) {
    // Spot failed, continue to futures
  }

  // 2. Fallback to Futures K-Lines
  try {
    const futuresUrl = `https://fapi.binance.com/fapi/v1/klines?symbol=${cleanSymbol}&interval=${interval}&limit=${limit}`;
    const response = await fetchWithFallback(futuresUrl);
    const data = JSON.parse(await response.text());
    if (Array.isArray(data) && data.length > 0) {
      return parseKlines(data);
    }
  } catch (e) {
    console.error(`Failed to fetch K-lines for ${cleanSymbol}`);
  }

  return "Data Unavailable";
};

/**
 * Fetch Futures Market Sentiment Data
 */
export const fetchFuturesMetrics = async (symbol: string): Promise<FuturesData> => {
  const cleanSymbol = symbol.replace('/', '').toUpperCase();
  try {
    // 1. Fetch Open Interest
    const oiUrl = `https://fapi.binance.com/fapi/v1/openInterest?symbol=${cleanSymbol}`;
    const oiRes = await fetchWithFallback(oiUrl);
    const oiData = JSON.parse(await oiRes.text());

    // 2. Fetch Long/Short Ratio (Global Account)
    const lsUrl = `https://fapi.binance.com/futures/data/globalLongShortAccountRatio?symbol=${cleanSymbol}&period=5m&limit=1`;
    const lsRes = await fetchWithFallback(lsUrl);
    const lsData = JSON.parse(await lsRes.text());

    return {
      openInterest: oiData.openInterest ? (parseFloat(oiData.openInterest) / 1000000).toFixed(2) + "M" : "N/A",
      longShortRatio: lsData[0] ? lsData[0].longShortRatio : "N/A"
    };
  } catch (e) {
    return { openInterest: "N/A", longShortRatio: "N/A" };
  }
};

export const fetchTopActivePairs = async (): Promise<BinanceTicker[]> => {
  try {
    const url = `https://api.binance.com/api/v3/ticker/24hr`;
    const response = await fetchWithFallback(url);
    const text = await response.text();
    if (!text) return [];
    const allTickers = JSON.parse(text) as BinanceTicker[];
    return allTickers
      .filter(t => t.symbol.endsWith('USDT') && !t.symbol.includes('UP') && !t.symbol.includes('DOWN') && !t.symbol.includes('USDC'))
      .filter(t => parseFloat(t.quoteVolume) > 50000000) 
      .sort((a, b) => Math.abs(parseFloat(b.priceChangePercent)) - Math.abs(parseFloat(a.priceChangePercent))) 
      .slice(0, 15); 
  } catch (error) {
    return [];
  }
};

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AnalysisResult, RecommendedTarget, BinanceTicker } from "../types";
import { fetchKlines, fetchFuturesMetrics } from "./fugleService";

const SYSTEM_INSTRUCTION = `
角色設定：
你是頂尖加密貨幣操盤手，擅長「分批止盈 (Scaling Out)」策略來鎖定利潤並將風險降至零。

**【數據校正準則 - 最高優先級】**
你必須確保分析是基於「真實即時價格」。
如果使用者提供的 API 價格為 0、數值異常，或者與你透過 Google Search 查到的價格有巨大落差，**請務必使用你搜尋到的真實價格進行分析**，並在報告中註明修正。

**【分批止盈策略 - 核心邏輯】**
你必須為每一筆交易計算三個止盈目標 (TP)：
1. **TP1 (保守/保本)**：約 1:1 到 1:1.5 的盈虧比，或最近的小時級別阻力/支撐。
2. **TP2 (技術滿足點)**：約 1:2 到 1:3 盈虧比。形態學測算的標準目標價。
3. **TP3 (趨勢延伸/夢想)**：約 1:4+ 盈虧比。下一個大級別關鍵位置。

**【分析框架】**
1. **形態學 (Patterns)**：優先尋找 W築底、M頭、杯柄型態、頭肩頂/底。
2. **合約數據**：參考提供的 OI 與多空比。
3. **五大指標共振**：EMA 排列、RSI 強弱、MACD 能量。

**操作紀律**：語言必須使用繁體中文。語氣專業、數據說話。
`;

export const getGeminiClient = (apiKey: string) => {
  if (!apiKey) return null;
  return new GoogleGenAI({ apiKey });
};

const cleanJsonText = (text: string): string => {
  if (!text) return "";
  return text.replace(/```json/g, "").replace(/```/g, "").trim();
};

export const analyzeSingleStock = async (
  apiKey: string,
  symbol: string,
  currentPrice: number
): Promise<AnalysisResult> => {
  const ai = getGeminiClient(apiKey);
  if (!ai) throw new Error("API Key missing");

  const cleanSymbol = symbol.replace('/', '').toUpperCase();
  const klines = await fetchKlines(cleanSymbol, '4h', 20);
  const futures = await fetchFuturesMetrics(cleanSymbol);

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      symbol: { type: Type.STRING },
      name: { type: Type.STRING },
      trend: { type: Type.STRING, enum: ['BULLISH', 'BEARISH', 'NEUTRAL'] },
      side: { type: Type.STRING, enum: ['LONG', 'SHORT', 'WAIT'] },
      entryPoint: { type: Type.NUMBER },
      takeProfit1: { type: Type.NUMBER, description: "Conservative target (R:R 1:1.5)" },
      takeProfit2: { type: Type.NUMBER, description: "Main technical target (R:R 1:3)" },
      takeProfit3: { type: Type.NUMBER, description: "Trend runner target (R:R 1:5+)" },
      stopLoss: { type: Type.NUMBER },
      leverage: { type: Type.NUMBER },
      analysisText: { type: Type.STRING },
      reasoning: { type: Type.STRING },
    },
    required: ["symbol", "trend", "side", "entryPoint", "takeProfit1", "takeProfit2", "takeProfit3", "stopLoss", "leverage", "analysisText", "reasoning"],
  };

  // Explicitly tell AI to use Google Search if price looks wrong (or is 0)
  const priceContext = currentPrice > 0 
    ? `API 抓取現價：${currentPrice} (若此價格看起來過時，請使用 Google Search 獲取最新報價)`
    : `API 抓取現價失敗 (0)。**請務必立刻使用 Google Search 查詢 ${cleanSymbol} 的最新合約價格**。`;

  const prompt = `分析交易對：${cleanSymbol}
  ${priceContext}
  4H K線序列 (新->舊): [${klines}]
  合約持倉量 (OI): ${futures.openInterest}
  多空帳戶比 (L/S): ${futures.longShortRatio}

  請執行：
  1. **確認價格**：如果 API 價格為 0，使用 Google Search 找到當前價格。
  2. **識別形態**：分析 K 線數列與型態 (W底、M頭等)。
  3. **策略制定**：給出明確的進場、止損與三階段止盈 (TP1/TP2/TP3)。

  請回傳繁體中文 JSON。`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview", 
    contents: prompt,
    config: { 
      systemInstruction: SYSTEM_INSTRUCTION, 
      tools: [{ googleSearch: {} }], // Enable search for single symbol analysis
      responseMimeType: "application/json", 
      responseSchema: schema, 
      temperature: 0.1 
    }
  });

  return JSON.parse(cleanJsonText(response.text || "{}")) as AnalysisResult;
};

export const getDailyRecommendations = async (apiKey: string, candidates: BinanceTicker[]): Promise<RecommendedTarget[]> => {
  const ai = getGeminiClient(apiKey);
  if (!ai) throw new Error("API Key missing");

  const topCandidates = candidates.slice(0, 6);
  const candidatesWithData = await Promise.all(topCandidates.map(async (c) => {
    const klines = await fetchKlines(c.symbol, '4h', 20);
    const futures = await fetchFuturesMetrics(c.symbol);
    return { ...c, klines, futures };
  }));

  const candidateInfo = candidatesWithData.map(c => 
    `Symbol: ${c.symbol} | Price: ${c.lastPrice} | 4H K: [${c.klines}] | OI: ${c.futures.openInterest} | L/S: ${c.futures.longShortRatio}`
  ).join('\n');

  const schema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        symbol: { type: Type.STRING },
        name: { type: Type.STRING },
        currentPrice: { type: Type.NUMBER },
        entryPrice: { type: Type.NUMBER },
        takeProfit1: { type: Type.NUMBER },
        takeProfit2: { type: Type.NUMBER },
        takeProfit3: { type: Type.NUMBER },
        stopLoss: { type: Type.NUMBER },
        side: { type: Type.STRING, enum: ['LONG', 'SHORT'] },
        leverage: { type: Type.NUMBER },
        suggestion: { type: Type.STRING, enum: ['ENTER_NOW', 'WAIT', 'WATCH'] },
        winRate: { type: Type.NUMBER },
        reason: { type: Type.STRING },
        detectedPattern: { type: Type.STRING },
        evidences: { type: Type.ARRAY, items: { type: Type.STRING } },
        openInterest: { type: Type.STRING },
        longShortRatio: { type: Type.STRING }
      },
      required: ["symbol", "name", "currentPrice", "entryPrice", "takeProfit1", "takeProfit2", "takeProfit3", "stopLoss", "side", "leverage", "suggestion", "winRate", "reason", "evidences", "detectedPattern", "openInterest", "longShortRatio"],
    },
  };

  const prompt = `檢測以下幣種數據：
  ${candidateInfo}

  **【深度掃描任務】**
  1. **型態識別**：找出是否有明顯的築底(W)或頂部(M)或杯柄型態。
  2. **籌碼過濾**：比對 OI 與價格走勢，確認資金是否正在進場。
  3. **止盈規劃**：嚴格計算三階段止盈 (TP1 保守, TP2 目標, TP3 延伸)。
  4. **極致篩選**：只選出勝率高於 85% 且風險報酬比大於 2 的標的。

  回傳 2-3 個推薦，繁體中文 JSON。`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview", 
    contents: prompt,
    config: { 
      systemInstruction: SYSTEM_INSTRUCTION, 
      tools: [{ googleSearch: {} }], // Keep search enabled for batch analysis too
      responseMimeType: "application/json", 
      responseSchema: schema, 
      temperature: 0.1 
    }
  });

  return JSON.parse(cleanJsonText(response.text || "[]")) as RecommendedTarget[];
};
